const MAX_EXACT_F64_INT: u128 = 1_u128 << 53;

fn py_dijkstra_weight_flags(raw: &Bound<'_, PyAny>, max_path_edges: u128) -> (bool, bool, bool) {
    if raw.is_exact_instance_of::<PyBool>() {
        return (false, false, false);
    }
    if raw.is_exact_instance_of::<PyInt>() {
        return raw.extract::<i64>().map_or((false, true, false), |value| {
            (
                value < 0,
                u128::from(value.unsigned_abs()) * max_path_edges > MAX_EXACT_F64_INT,
                false,
            )
        });
    }
    if raw.is_exact_instance_of::<PyFloat>() {
        return raw.extract::<f64>().map_or((false, false, true), |value| {
            (value < 0.0, !value.is_finite(), false)
        });
    }
    // NetworkX preserves arithmetic and return types for custom numeric
    // objects (Fraction, Decimal, NumPy scalars). The native Cgse/f64 path
    // cannot, so keep those on the exact delegation route.
    (false, false, true)
}

fn stored_dijkstra_weight_flags(
    raw: Option<&fnx_runtime::CgseValue>,
    max_path_edges: u128,
) -> (bool, bool, bool) {
    match raw {
        None | Some(fnx_runtime::CgseValue::Bool(_)) => (false, false, false),
        Some(fnx_runtime::CgseValue::Int(value)) => (
            *value < 0,
            u128::from(value.unsigned_abs()) * max_path_edges > MAX_EXACT_F64_INT,
            false,
        ),
        Some(fnx_runtime::CgseValue::Float(value)) => (*value < 0.0, !value.is_finite(), false),
        Some(fnx_runtime::CgseValue::String(_)) | Some(fnx_runtime::CgseValue::Map(_)) => {
            (false, false, true)
        }
    }
}

#[pyfunction]
#[pyo3(signature = (g, weight_attr, require_exact_string_nodes=false))]
pub fn check_dijkstra_edge_weights_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    weight_attr: &str,
    require_exact_string_nodes: bool,
) -> PyResult<Option<(bool, bool, bool)>> {
    let gr = extract_graph(g)?;
    match &gr {
        GraphRef::Undirected(pg) => {
            let mut has_negative = false;
            let mut has_nonfinite = false;
            let mut has_nonnumeric = false;
            for dict in pg.edge_py_attrs.values() {
                let bound = dict.bind(py);
                if let Some(val) = bound.get_item(weight_attr)? {
                    if let Ok(f) = val.extract::<f64>() {
                        if f < 0.0 {
                            has_negative = true;
                        }
                        if !f.is_finite() {
                            has_nonfinite = true;
                        }
                    } else if let Ok(i) = val.extract::<i64>() {
                        if i < 0 {
                            has_negative = true;
                        }
                    } else if val.extract::<bool>().is_err() {
                        has_nonnumeric = true;
                    }
                }
                if has_negative && has_nonfinite && has_nonnumeric {
                    break;
                }
            }
            Ok(Some((has_negative, has_nonfinite, has_nonnumeric)))
        }
        GraphRef::Directed { dg, .. } => {
            let mut has_negative = false;
            let mut has_nonfinite = false;
            let mut has_nonnumeric = false;
            for dict in dg.edge_py_attrs.values() {
                let bound = dict.bind(py);
                if let Some(val) = bound.get_item(weight_attr)? {
                    if let Ok(f) = val.extract::<f64>() {
                        if f < 0.0 {
                            has_negative = true;
                        }
                        if !f.is_finite() {
                            has_nonfinite = true;
                        }
                    } else if let Ok(i) = val.extract::<i64>() {
                        if i < 0 {
                            has_negative = true;
                        }
                    } else if val.extract::<bool>().is_err() {
                        has_nonnumeric = true;
                    }
                }
                if has_negative && has_nonfinite && has_nonnumeric {
                    break;
                }
            }
            Ok(Some((has_negative, has_nonfinite, has_nonnumeric)))
        }
        GraphRef::MultiUndirected { mg, .. } => {
            if !require_exact_string_nodes {
                // Preserve the established shared classifier for unrelated
                // MultiGraph Dijkstra APIs. The stricter exact-domain checks
                // below belong only to the new string-key bidirectional path.
                let mut has_negative = false;
                let mut has_positive_infinity = false;
                let mut has_nonnumeric = false;
                for dict in mg.edge_py_attrs.values() {
                    let bound = dict.bind(py);
                    if let Some(val) = bound.get_item(weight_attr)? {
                        if let Ok(f) = val.extract::<f64>() {
                            if f < 0.0 {
                                has_negative = true;
                            }
                            if f.is_infinite() && f.is_sign_positive() {
                                has_positive_infinity = true;
                            }
                        } else if let Ok(i) = val.extract::<i64>() {
                            if i < 0 {
                                has_negative = true;
                            }
                        } else if val.extract::<bool>().is_err() {
                            has_nonnumeric = true;
                        }
                    }
                    if has_negative && has_positive_infinity && has_nonnumeric {
                        break;
                    }
                }
                return Ok(Some((has_negative, has_positive_infinity, has_nonnumeric)));
            }

            let mut has_negative = false;
            let mut has_nonfinite_or_inexact_int = false;
            // The native path emitter resolves graph-global display objects,
            // while NetworkX records the object first seen in each adjacency
            // row. Hash-equal mixed node objects (for example `1` / `1.0`) and
            // string subclasses therefore need the exact Python traversal.
            // The measured lane is exact built-in string nodes, for which this
            // native O(V) mirror check is allocation-free.
            let mut has_nonnumeric = require_exact_string_nodes
                && (!mg.adj_py_keys.is_empty()
                    || mg.node_key_map.len() != mg.inner.node_count()
                    || mg
                        .node_key_map
                        .values()
                        .any(|node| !node.bind(py).is_exact_instance_of::<PyString>()));
            let max_path_edges = mg.inner.node_count().saturating_sub(1).max(1) as u128;
            for dict in mg.edge_py_attrs.values() {
                let bound = dict.bind(py);
                if bound
                    .iter()
                    .any(|(key, _)| !key.is_exact_instance_of::<PyString>())
                {
                    // Rust canonicalizes attribute keys to strings. A Python
                    // non-string key can collide with `weight_attr` after that
                    // conversion, so the original dict must stay authoritative.
                    has_nonnumeric = true;
                }
                if let Some(val) = bound.get_item(weight_attr)? {
                    let flags = py_dijkstra_weight_flags(&val, max_path_edges);
                    has_negative |= flags.0;
                    has_nonfinite_or_inexact_int |= flags.1;
                    has_nonnumeric |= flags.2;
                }
                if has_negative && has_nonfinite_or_inexact_int && has_nonnumeric {
                    break;
                }
            }
            // Graph conversions may keep authoritative attributes only in the
            // Rust store. Fully mirrored graphs stay on the allocation-free
            // loop above; empty/partial mirrors additionally inspect store-only
            // edges so hostile weights cannot slip into the native kernel.
            if mg.edge_py_attrs.len() < mg.inner.edge_count() {
                for (left, right, key, attrs) in mg.inner.edges_ordered_borrowed() {
                    let is_mirrored = if mg.edge_py_attrs.is_empty() {
                        false
                    } else {
                        mg.edge_py_attrs
                            .contains_key(&PyMultiGraph::edge_key(left, right, key))
                    };
                    if is_mirrored {
                        continue;
                    }
                    let flags =
                        stored_dijkstra_weight_flags(attrs.get(weight_attr), max_path_edges);
                    has_negative |= flags.0;
                    has_nonfinite_or_inexact_int |= flags.1;
                    has_nonnumeric |= flags.2;
                    if has_negative && has_nonfinite_or_inexact_int && has_nonnumeric {
                        break;
                    }
                }
            }
            Ok(Some((
                has_negative,
                has_nonfinite_or_inexact_int,
                has_nonnumeric,
            )))
        }
        GraphRef::MultiDirected { mdg, .. } => {
            let mut has_negative = false;
            let mut has_positive_infinity = false;
            let mut has_nonnumeric = false;
            for dict in mdg.edge_py_attrs.values() {
                let bound = dict.bind(py);
                if let Some(val) = bound.get_item(weight_attr)? {
                    if let Ok(f) = val.extract::<f64>() {
                        if f < 0.0 {
                            has_negative = true;
                        }
                        if f.is_infinite() && f.is_sign_positive() {
                            has_positive_infinity = true;
                        }
                    } else if let Ok(i) = val.extract::<i64>() {
                        if i < 0 {
                            has_negative = true;
                        }
                    } else if val.extract::<bool>().is_err() {
                        has_nonnumeric = true;
                    }
                }
                if has_negative && has_positive_infinity && has_nonnumeric {
                    break;
                }
            }
            Ok(Some((has_negative, has_positive_infinity, has_nonnumeric)))
        }
    }
}

#[pyfunction]
#[pyo3(signature = (g))]
pub fn dijkstra_weight_cache_token(g: &Bound<'_, PyAny>) -> PyResult<Option<(u64, u64, bool)>> {
    let gr = extract_graph(g)?;
    match &gr {
        GraphRef::Undirected(pg) => Ok(Some((
            pg.nodes_seq,
            pg.edges_seq,
            pg.edges_dirty.load(Ordering::Relaxed),
        ))),
        GraphRef::Directed { dg, .. } => Ok(Some((
            dg.nodes_seq,
            dg.edges_seq,
            dg.edges_dirty.load(Ordering::Relaxed),
        ))),
        GraphRef::MultiUndirected { .. } | GraphRef::MultiDirected { .. } => Ok(None),
    }
}

#[pyfunction]
#[pyo3(signature = (g, source, target, weight="weight"))]
pub fn dijkstra_path(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<Vec<PyObject>> {
    sync_rust_attrs_for_non_simple(g)?;
    let gr = extract_graph(g)?;
    let s = node_key_to_string(py, source)?;
    let t = node_key_to_string(py, target)?;
    validate_node(&gr, &s, source, "Source")?;
    validate_node(&gr, &t, target, "Target")?;

    let result =
        if let Some(weighted_projection) = gr.dijkstra_weighted_digraph_projection(py, weight)? {
            {
                let __wp = weighted_projection.as_ref();
                py.allow_threads(|| {
                    fnx_algorithms::shortest_path_weighted_directed(__wp, &s, &t, weight)
                })
            }
        } else {
            let weighted_projection = gr.dijkstra_weighted_undirected_projection(py, weight)?;
            {
                let __wp = weighted_projection.as_ref();
                py.allow_threads(|| fnx_algorithms::shortest_path_weighted(__wp, &s, &t, weight))
            }
        };
    match result.path {
        Some(p) => Ok(p.iter().map(|n| gr.py_node_key(py, n)).collect()),
        None => Err(NetworkXNoPath::new_err(format!(
            "No path between {} and {}.",
            s, t
        ))),
    }
}

// ---------------------------------------------------------------------------
// bellman_ford_path
// ---------------------------------------------------------------------------

#[pyfunction]
#[pyo3(signature = (g, source, target, weight="weight"))]
pub fn bellman_ford_path(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<Vec<PyObject>> {
    sync_rust_attrs_if_available(g)?;
    let gr = extract_graph(g)?;
    let s = node_key_to_string(py, source)?;
    let t = node_key_to_string(py, target)?;
    validate_node(&gr, &s, source, "Source")?;
    validate_node(&gr, &t, target, "Target")?;

    let result = if let Some(weighted_projection) = gr.weighted_digraph_projection(weight) {
        {
            let __wp = weighted_projection.as_ref();
            py.allow_threads(|| {
                fnx_algorithms::bellman_ford_shortest_paths_directed(__wp, &s, weight)
            })
        }
    } else {
        let weighted_projection = gr.weighted_undirected_projection(weight);
        {
            let __wp = weighted_projection.as_ref();
            py.allow_threads(|| fnx_algorithms::bellman_ford_shortest_paths(__wp, &s, weight))
        }
    };
    if result.negative_cycle_detected {
        return Err(crate::NetworkXUnbounded::new_err(
            "Negative cost cycle detected.",
        ));
    }

    let pred_map: std::collections::HashMap<&str, Option<&str>> = result
        .predecessors
        .iter()
        .map(|e| (e.node.as_str(), e.predecessor.as_deref()))
        .collect();

    if !pred_map.contains_key(t.as_str()) {
        return Err(NetworkXNoPath::new_err(format!(
            "No path between {} and {}.",
            s, t
        )));
    }

    let mut path = vec![t.clone()];
    let mut current = t.as_str();
    while current != s {
        match pred_map.get(current) {
            Some(Some(prev)) => {
                path.push((*prev).to_owned());
                current = prev;
            }
            _ => {
                return Err(NetworkXNoPath::new_err(format!(
                    "No path between {} and {}.",
                    s, t
                )));
            }
        }
    }
    path.reverse();
    Ok(path.iter().map(|n| gr.py_node_key(py, n)).collect())
}

// ---------------------------------------------------------------------------
// multi_source_dijkstra
// ---------------------------------------------------------------------------

#[pyfunction]
#[pyo3(signature = (g, sources, weight="weight"))]
/// br-r37-c1-2z0mw (cc): for each reachable node, the nearest SOURCE (center) on its
/// shortest path — what ``voronoi_cells`` consumes (``path[0]`` of multi_source) — without
/// building any paths. Returns a list of ``(node, source)`` in finalize (distance) order,
/// byte-identical to ``{v: paths[v][0]}``. Undirected only; the wrapper falls back for
/// directed / callable weight.
pub fn multi_source_nearest_source(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    sources: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<Py<pyo3::types::PyList>> {
    let gr = extract_graph(g)?;
    let iter = pyo3::types::PyIterator::from_object(sources)?;
    let mut source_strs: Vec<String> = Vec::new();
    for item in iter {
        let item = item?;
        source_strs.push(node_key_to_string(py, &item)?);
    }
    let source_refs: Vec<&str> = source_strs.iter().map(String::as_str).collect();
    let weighted_projection = gr.dijkstra_weighted_undirected_projection(py, weight)?;
    let result = {
        let __wp = weighted_projection.as_ref();
        py.allow_threads(|| {
            fnx_algorithms::multi_source_dijkstra_nearest_source(__wp, &source_refs, weight)
        })
    };
    let out = pyo3::types::PyList::empty(py);
    for (node, source) in &result {
        out.append((gr.py_node_key(py, node), gr.py_node_key(py, source)))?;
    }
    Ok(out.unbind())
}

#[pyfunction]
#[pyo3(signature = (g, sources, weight="weight"))]
pub fn multi_source_dijkstra(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    sources: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<(PyObject, PyObject)> {
    // br-r37-c1-msd-projfix (cc): sync the Python edge-attr mirror to the store
    // (for simple graphs too) and run the kernel on the BORROWED ORIGINAL graph
    // (`weighted_*_projection`) rather than the REBUILT `dijkstra_*_projection`,
    // whose adjacency-reordering rebuild made the finalize order diverge from nx
    // on dense graphs (see multi_source_dijkstra_path_length resolution). The
    // borrow also drops the per-call O(E) rebuild. Identical to how
    // single_source_dijkstra binds.
    sync_rust_attrs_if_available(g)?;
    let gr = extract_graph(g)?;
    let iter = pyo3::types::PyIterator::from_object(sources)?;
    let mut source_strs = Vec::new();
    // br-r37-c1-7hsew: keep the PASSED source objects — nx seeds
    // `{source: [source] for source in sources}`, so sources display AS
    // PASSED (iterating the caller's set object in-process also gives
    // nx's exact seed order at any hash seed).
    let mut seed_objs: std::collections::HashMap<String, PyObject> =
        std::collections::HashMap::new();
    for item in iter {
        let item = item?;
        let s = node_key_to_string(py, &item)?;
        validate_node_str(&gr, &s, "Source")?;
        seed_objs.entry(s.clone()).or_insert_with(|| item.unbind());
        source_strs.push(s);
    }
    let source_refs: Vec<&str> = source_strs.iter().map(String::as_str).collect();

    let result = if let Some(weighted_projection) = gr.weighted_digraph_projection(weight) {
        {
            let __wp = weighted_projection.as_ref();
            py.allow_threads(|| {
                fnx_algorithms::multi_source_dijkstra_directed(__wp, &source_refs, weight)
            })
        }
    } else {
        let weighted_projection = gr.weighted_undirected_projection(weight);
        {
            let __wp = weighted_projection.as_ref();
            py.allow_threads(|| fnx_algorithms::multi_source_dijkstra(__wp, &source_refs, weight))
        }
    };

    let pred_map: std::collections::HashMap<&str, Option<&str>> = result
        .predecessors
        .iter()
        .map(|e| (e.node.as_str(), e.predecessor.as_deref()))
        .collect();

    // br-r37-c1-7hsew: discovery objects — seeds as passed, every other
    // node as its finalizing predecessor's row object.
    let mut disp: std::collections::HashMap<String, PyObject> = seed_objs;
    for entry in &result.distances {
        if let Some(Some(p)) = pred_map.get(entry.node.as_str()) {
            disp.entry(entry.node.clone())
                .or_insert_with(|| gr.py_row_key(py, p, &entry.node));
        }
    }

    let dist_dict = PyDict::new(py);
    for entry in &result.distances {
        dist_dict.set_item(gr.disp_or_node_key(py, &disp, &entry.node), entry.distance)?;
    }

    let paths_dict = PyDict::new(py);
    for entry in &result.distances {
        let mut path = vec![entry.node.clone()];
        let mut current = entry.node.as_str();
        while let Some(Some(prev)) = pred_map.get(current) {
            path.push((*prev).to_owned());
            current = prev;
        }
        path.reverse();
        let py_path: Vec<PyObject> = path
            .iter()
            .map(|n| gr.disp_or_node_key(py, &disp, n))
            .collect();
        paths_dict.set_item(gr.disp_or_node_key(py, &disp, &entry.node), py_path)?;
    }

    Ok((
        dist_dict.into_any().unbind(),
        paths_dict.into_any().unbind(),
    ))
}

/// Length-only multi-source Dijkstra: returns just `{node: distance}` in the
/// kernel's FINALIZE (heap-pop) order, skipping the O(V*path_len) `paths_dict`.
///
/// CRITICAL (br-r37-c1-msd-projfix cc): unlike `multi_source_dijkstra`, this
/// syncs the Python edge-attr mirror to the store and runs the kernel on the
/// BORROWED ORIGINAL graph (`weighted_*_projection`) — NOT the REBUILT
/// `dijkstra_*_projection`, whose `dijkstra_single_weight_graph_projection`
/// rebuild REORDERS per-node adjacency, which shifts the heap push-sequence and
/// makes the finalize order diverge from NetworkX on DENSE tie-heavy graphs
/// (the single_source kernel is correct precisely because it sync+borrows the
/// original). With the original adjacency the finalize order is byte-identical
/// to nx's `(distance, next(c))` pop order. The Python wrapper gates to integer
/// weights (float/mixed keep the delegated path for per-node int-typing).
#[pyfunction]
#[pyo3(signature = (g, sources, weight="weight"))]
pub fn multi_source_dijkstra_path_length(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    sources: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<PyObject> {
    sync_rust_attrs_if_available(g)?;
    let gr = extract_graph(g)?;
    let iter = pyo3::types::PyIterator::from_object(sources)?;
    let mut source_strs = Vec::new();
    let mut seed_objs: std::collections::HashMap<String, PyObject> =
        std::collections::HashMap::new();
    for item in iter {
        let item = item?;
        let s = node_key_to_string(py, &item)?;
        validate_node_str(&gr, &s, "Source")?;
        seed_objs.entry(s.clone()).or_insert_with(|| item.unbind());
        source_strs.push(s);
    }
    let source_refs: Vec<&str> = source_strs.iter().map(String::as_str).collect();

    let result = if let Some(weighted_projection) = gr.weighted_digraph_projection(weight) {
        let __wp = weighted_projection.as_ref();
        py.allow_threads(|| {
            fnx_algorithms::multi_source_dijkstra_directed(__wp, &source_refs, weight)
        })
    } else {
        let weighted_projection = gr.weighted_undirected_projection(weight);
        let __wp = weighted_projection.as_ref();
        py.allow_threads(|| fnx_algorithms::multi_source_dijkstra(__wp, &source_refs, weight))
    };

    let pred_map: std::collections::HashMap<&str, Option<&str>> = result
        .predecessors
        .iter()
        .map(|e| (e.node.as_str(), e.predecessor.as_deref()))
        .collect();
    let mut disp: std::collections::HashMap<String, PyObject> = seed_objs;
    for entry in &result.distances {
        if let Some(Some(p)) = pred_map.get(entry.node.as_str()) {
            disp.entry(entry.node.clone())
                .or_insert_with(|| gr.py_row_key(py, p, &entry.node));
        }
    }

    let dist_dict = PyDict::new(py);
    for entry in &result.distances {
        dist_dict.set_item(gr.disp_or_node_key(py, &disp, &entry.node), entry.distance)?;
    }
    Ok(dist_dict.into_any().unbind())
}

// ---------------------------------------------------------------------------
// bidirectional_dijkstra (undirected native kernel, br-r37-c1-k4p0b)
// ---------------------------------------------------------------------------

/// Native bidirectional Dijkstra: returns `(length, path)`
/// byte-identical to `networkx.bidirectional_dijkstra`. The Python wrapper only
/// routes simple graphs and undirected `MultiGraph`s with a string weight key
/// and non-negative finite numeric weights here (everything else is delegated);
/// it also performs the nx `NodeNotFound` checks before calling, so this kernel
/// assumes both nodes are present.
fn bidirectional_dijkstra_with_multigraph_kernel(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
    multigraph_kernel: fn(
        &fnx_classes::MultiGraph,
        &str,
        &str,
        &str,
    ) -> fnx_algorithms::BidirectionalDijkstraOutcome,
) -> PyResult<(f64, bool, PyObject)> {
    // The Python wrapper has already run the edge-only, dirty-gated
    // `_fnx_sync_edge_attrs_to_inner` (a no-op for unmutated graphs), so the
    // inner AttrMap weights this kernel reads are current. We deliberately do
    // NOT call the heavy `_fnx_sync_attrs_to_inner` here: it unconditionally
    // re-syncs all node attrs (O(n)) on every call, which dominated the
    // single-pair cost and made the native kernel slower than nx.
    let gr = extract_graph(g)?;
    let source_str = node_key_to_string(py, source)?;
    let target_str = node_key_to_string(py, target)?;
    validate_node_str(&gr, &source_str, "Source")?;
    validate_node_str(&gr, &target_str, "Target")?;

    // br-r37-c1-04z53.9170: an undirected MultiGraph must not take the projected
    // simple-graph route. Projection both dominated this public row and can
    // reorder per-node adjacency, changing NetworkX's meeting-node tie-break.
    let outcome = match &gr {
        GraphRef::MultiUndirected { mg, .. } => {
            let inner = &mg.inner;
            py.allow_threads(|| multigraph_kernel(inner, &source_str, &target_str, weight))
        }
        _ => {
            // br-r37-c1-p60i1 (cc): directed graphs route to the directed kernel
            // (forward successors / backward predecessors); simple undirected
            // graphs keep the original integer-adjacency kernel.
            if let Some(projection) = gr.weighted_digraph_projection(weight) {
                let inner = projection.as_ref();
                py.allow_threads(|| {
                    fnx_algorithms::bidirectional_dijkstra_directed(
                        inner,
                        &source_str,
                        &target_str,
                        weight,
                    )
                })
            } else {
                let projection = gr.weighted_undirected_projection(weight);
                let inner = projection.as_ref();
                py.allow_threads(|| {
                    fnx_algorithms::bidirectional_dijkstra_undirected(
                        inner,
                        &source_str,
                        &target_str,
                        weight,
                    )
                })
            }
        }
    };

    match outcome {
        fnx_algorithms::BidirectionalDijkstraOutcome::Found(length, all_int, path) => {
            let py_path: Vec<PyObject> = path.iter().map(|n| gr.py_node_key(py, n)).collect();
            Ok((
                length,
                all_int,
                py_path.into_pyobject(py)?.into_any().unbind(),
            ))
        }
        fnx_algorithms::BidirectionalDijkstraOutcome::NoPath => Err(NetworkXNoPath::new_err(
            format!("No path between {} and {}.", source.str()?, target.str()?),
        )),
        fnx_algorithms::BidirectionalDijkstraOutcome::Contradiction => Err(PyValueError::new_err(
            "Contradictory paths found: negative weights?",
        )),
        fnx_algorithms::BidirectionalDijkstraOutcome::NodeMissing => {
            Err(NodeNotFound::new_err(format!(
                "Either source {} or target {} is not in G",
                source.str()?,
                target.str()?
            )))
        }
    }
}

#[pyfunction]
#[pyo3(signature = (g, source, target, weight="weight"))]
pub fn bidirectional_dijkstra(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<(f64, bool, PyObject)> {
    bidirectional_dijkstra_with_multigraph_kernel(
        py,
        g,
        source,
        target,
        weight,
        multigraph_bidirectional_dijkstra,
    )
}

/// Frozen current-native reference for the paired performance harness. It
/// shares endpoint canonicalisation, validation, GIL release, and result
/// marshalling with the candidate; only the MultiGraph node-ID substrate
/// differs.
#[cfg(feature = "bench-internals")]
#[pyfunction(name = "_bench_bidirectional_dijkstra_orig")]
#[pyo3(signature = (g, source, target, weight="weight"))]
fn bench_bidirectional_dijkstra_orig(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<(f64, bool, PyObject)> {
    bidirectional_dijkstra_with_multigraph_kernel(
        py,
        g,
        source,
        target,
        weight,
        multigraph_bidirectional_dijkstra_orig,
    )
}

/// br-r37-c1-lc2qy (cc): single-pair weighted Dijkstra PATH with target early-exit.
///
/// Returns ``(length, all_int, path)`` or raises ``NetworkXNoPath`` if the target is
/// unreachable. Routes directed/undirected to the matching target-early-exit kernel, which
/// stops when the target finalizes and reconstructs ONLY the target path (skipping the
/// all-paths construction that made single-pair ``single_source_dijkstra_path[target]``
/// slow). Byte-identical to ``networkx.dijkstra_path``. The wrapper has already validated
/// the source and edge-only-synced post-construction weight mutations.
#[pyfunction]
pub fn dijkstra_path_to_target(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    source: &Bound<'_, PyAny>,
    target: &Bound<'_, PyAny>,
    weight: &str,
) -> PyResult<(f64, bool, PyObject)> {
    let gr = extract_graph(g)?;
    let source_str = node_key_to_string(py, source)?;
    let target_str = node_key_to_string(py, target)?;
    let outcome = if let Some(projection) = gr.weighted_digraph_projection(weight) {
        let inner = projection.as_ref();
        py.allow_threads(|| {
            fnx_algorithms::dijkstra_path_to_target_directed(
                inner,
                &source_str,
                &target_str,
                weight,
            )
        })
    } else if let GraphRef::MultiUndirected { mg, .. } = &gr {
        let inner = &mg.inner;
        py.allow_threads(|| {
            multigraph_dijkstra_path_to_target_lazy(inner, &source_str, &target_str, weight)
        })
    } else {
        let projection = gr.weighted_undirected_projection(weight);
        let inner = projection.as_ref();
        py.allow_threads(|| {
            fnx_algorithms::dijkstra_path_to_target(inner, &source_str, &target_str, weight)
        })
    };
    match outcome {
        Some((length, path, all_int)) => {
            let py_path: Vec<PyObject> = path.iter().map(|n| gr.py_node_key(py, n)).collect();
            Ok((
                length,
                all_int,
                py_path.into_pyobject(py)?.into_any().unbind(),
            ))
        }
        None => Err(NetworkXNoPath::new_err(format!(
            "No path to {}.",
            target_str
        ))),
    }
}

// ===========================================================================
// Connectivity algorithms
// ===========================================================================

/// Return True if the graph is connected, False otherwise.
///
/// Parameters
/// ----------
/// G : Graph
///     An undirected graph.
///
/// Returns
/// -------
/// connected : bool
///     True if the graph is connected.
///
/// Raises
/// ------
/// NetworkXNotImplemented
///     If the graph is directed.
/// br-r37-c1-fyxma2 (cc): is a MultiGraph connected? early-exit BFS from the first
/// node over the adjacency (no intermediate simple-Graph build, multiplicity is
/// irrelevant to connectivity) — same lever that fixed connected_components.
fn multigraph_is_connected(mg: &fnx_classes::MultiGraph) -> bool {
    use std::collections::VecDeque;

    if mg.node_count() == 0 {
        return true; // null graph; caller raises before reaching here
    }

    mg.with_int_adjacency(|adjacency| {
        let mut visited = vec![false; adjacency.len()];
        let mut visited_count = 1usize;
        let mut queue: VecDeque<usize> = VecDeque::new();
        visited[0] = true;
        queue.push_back(0);
        while let Some(node_idx) = queue.pop_front() {
            for &neighbor_idx in &adjacency[node_idx] {
                if !visited[neighbor_idx] {
                    visited[neighbor_idx] = true;
                    visited_count += 1;
                    queue.push_back(neighbor_idx);
                }
            }
        }
        visited_count == adjacency.len()
    })
}

/// Frozen pre-`br-r37-c1-59jm4` String-hashed traversal for exact A/B proof.
#[cfg(test)]
fn multigraph_is_connected_orig_string(mg: &fnx_classes::MultiGraph) -> bool {
    use std::collections::VecDeque;

    let nodes = mg.nodes_ordered();
    if nodes.is_empty() {
        return true;
    }
    let mut visited: rustc_hash::FxHashSet<&str> =
        rustc_hash::FxHashSet::with_capacity_and_hasher(nodes.len(), Default::default());
    let start = nodes[0];
    visited.insert(start);
    let mut queue: VecDeque<&str> = VecDeque::new();
    queue.push_back(start);
    while let Some(node) = queue.pop_front() {
        if let Some(neighbors) = mg.neighbors_iter(node) {
            for neighbor in neighbors {
                if visited.insert(neighbor) {
                    queue.push_back(neighbor);
                }
            }
        }
    }
    visited.len() == nodes.len()
}

/// br-r37-c1-fyxma2 (cc): the connected component containing `start` in a MultiGraph,
/// by direct BFS over the adjacency.
fn multigraph_node_connected_component<'a>(
    mg: &'a fnx_classes::MultiGraph,
    start: &str,
) -> Vec<&'a str> {
    use std::collections::VecDeque;

    let nodes = mg.nodes_ordered();
    let Some(start_idx) = mg.get_node_index(start) else {
        return Vec::new();
    };

    mg.with_int_adjacency(|adjacency| {
        let mut comp: Vec<&'a str> = Vec::new();
        let mut visited = vec![false; adjacency.len()];
        let mut queue: VecDeque<usize> = VecDeque::new();
        visited[start_idx] = true;
        comp.push(nodes[start_idx]);
        queue.push_back(start_idx);
        while let Some(node_idx) = queue.pop_front() {
            for &neighbor_idx in &adjacency[node_idx] {
                if !visited[neighbor_idx] {
                    visited[neighbor_idx] = true;
                    comp.push(nodes[neighbor_idx]);
                    queue.push_back(neighbor_idx);
                }
            }
        }
        comp
    })
}

/// Frozen pre-`br-r37-c1-85ktt` String-hashed traversal for exact A/B proof.
#[cfg(test)]
fn multigraph_node_connected_component_orig_string<'a>(
    mg: &'a fnx_classes::MultiGraph,
    start: &str,
) -> Vec<&'a str> {
    use std::collections::VecDeque;

    let mut comp: Vec<&'a str> = Vec::new();
    let nodes = mg.nodes_ordered();
    let start_ref: &'a str = match nodes.iter().copied().find(|&node| node == start) {
        Some(node) => node,
        None => return comp,
    };
    let mut visited: rustc_hash::FxHashSet<&'a str> = rustc_hash::FxHashSet::default();
    visited.insert(start_ref);
    comp.push(start_ref);
    let mut queue: VecDeque<&'a str> = VecDeque::new();
    queue.push_back(start_ref);
    while let Some(node) = queue.pop_front() {
        if let Some(neighbors) = mg.neighbors_iter(node) {
            for neighbor in neighbors {
                if visited.insert(neighbor) {
                    comp.push(neighbor);
                    queue.push_back(neighbor);
                }
            }
        }
    }
    comp
}

/// br-r37-c1-fyxma3 (cc): single-source BFS distances + discovery parents over a
/// MultiGraph's adjacency directly (no intermediate simple-Graph build). Distance is
/// multiplicity-invariant, and processing mg.neighbors() in adjacency order yields the
/// same discovery parents as nx's BFS over the converted simple graph. Returns
/// (node, length, parent) in BFS-discovery order, matching the simple-graph kernel.
fn multigraph_sssp_length_with_parents<'a>(
    mg: &'a fnx_classes::MultiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> Vec<(&'a str, usize, Option<&'a str>)> {
    use std::collections::VecDeque;
    // br-r37-c1-thp6w slice 2 (cc): BFS over the memoized INTEGER adjacency
    // (`with_int_adjacency`) with a `Vec<bool>` mark array + integer queue, instead of a
    // fresh `mg.neighbors(node)` `Vec<&str>` alloc per pop + a `HashSet<&str>` (String
    // hashing). `adj[i]` lists the distinct neighbors of node `i` in the SAME adjacency-row
    // order `mg.neighbors` yields, so BFS discovery order — hence every `(node, length,
    // parent)` tuple — is byte-identical; indices map back through `nodes` at the end.
    // On repeated single-source calls over an unmutated graph (all-pairs), the memo is
    // built once and reused across every source.
    let nodes = mg.nodes_ordered();
    let Some(source_idx) = mg.get_node_index(source) else {
        return Vec::new();
    };
    let n = nodes.len();
    let discovered: Vec<(usize, usize, Option<usize>)> = mg.with_int_adjacency(|adj| {
        let mut visited = vec![false; n];
        let mut disc: Vec<(usize, usize, Option<usize>)> = Vec::new();
        visited[source_idx] = true;
        disc.push((source_idx, 0, None));
        let mut queue: VecDeque<(usize, usize)> = VecDeque::new();
        queue.push_back((source_idx, 0));
        while let Some((node, dist)) = queue.pop_front() {
            if let Some(c) = cutoff
                && dist >= c
            {
                continue;
            }
            for &v in &adj[node] {
                if !visited[v] {
                    visited[v] = true;
                    disc.push((v, dist + 1, Some(node)));
                    queue.push_back((v, dist + 1));
                }
            }
        }
        disc
    });
    discovered
        .into_iter()
        .map(|(ni, d, pi)| (nodes[ni], d, pi.map(|p| nodes[p])))
        .collect()
}

/// br-r37-c1-thp6w slice 2 A/B baseline: the pre-lever `multigraph_sssp_length_with_parents`
/// (fresh `mg.neighbors(node)` `Vec<&str>` per pop + `HashSet<&str>` visited). Test-only;
/// byte-identical to the integer-adjacency version.
#[cfg(test)]
fn multigraph_sssp_length_with_parents_orig_string<'a>(
    mg: &'a fnx_classes::MultiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> Vec<(&'a str, usize, Option<&'a str>)> {
    use std::collections::{HashSet, VecDeque};
    let mut out: Vec<(&'a str, usize, Option<&'a str>)> = Vec::new();
    let nodes = mg.nodes_ordered();
    let source_ref: &'a str = match nodes.iter().copied().find(|&n| n == source) {
        Some(s) => s,
        None => return out,
    };
    let mut visited: HashSet<&'a str> = HashSet::new();
    visited.insert(source_ref);
    out.push((source_ref, 0, None));
    let mut queue: VecDeque<(&'a str, usize)> = VecDeque::new();
    queue.push_back((source_ref, 0));
    while let Some((node, dist)) = queue.pop_front() {
        if let Some(c) = cutoff
            && dist >= c
        {
            continue;
        }
        if let Some(nbrs) = mg.neighbors(node) {
            for v in nbrs {
                if visited.insert(v) {
                    out.push((v, dist + 1, Some(node)));
                    queue.push_back((v, dist + 1));
                }
            }
        }
    }
    out
}

/// br-r37-c1-kk2xh: simple Graph single-source shortest paths stay in
/// node-index space and emit from a predecessor table, matching the MultiGraph
/// path emitter without allocating one full path Vec per discovered target.
fn graph_sssp_predecessors_index<'a>(
    graph: &'a fnx_classes::Graph,
    source: &str,
    cutoff: Option<usize>,
) -> (Vec<&'a str>, Option<usize>, Vec<usize>, Vec<usize>) {
    let nodes = graph.nodes_ordered();
    let Some(source_idx) = graph.get_node_index(source) else {
        return (nodes, None, Vec::new(), Vec::new());
    };

    let n = nodes.len();
    let mut seen = vec![false; n];
    let mut predecessor = vec![usize::MAX; n];
    let mut discovery = Vec::with_capacity(n);
    let mut frontier = vec![source_idx];
    let mut next = Vec::new();
    let mut depth = 0usize;

    seen[source_idx] = true;
    discovery.push(source_idx);

    while !frontier.is_empty() {
        if cutoff.is_some_and(|limit| depth >= limit) {
            break;
        }
        next.clear();
        for &node_idx in &frontier {
            let Some(neighbors) = graph.neighbors_indices(node_idx) else {
                continue;
            };
            for &neighbor_idx in neighbors {
                if neighbor_idx < n && !seen[neighbor_idx] {
                    seen[neighbor_idx] = true;
                    predecessor[neighbor_idx] = node_idx;
                    discovery.push(neighbor_idx);
                    next.push(neighbor_idx);
                }
            }
        }
        std::mem::swap(&mut frontier, &mut next);
        depth += 1;
    }

    (nodes, Some(source_idx), discovery, predecessor)
}

/// br-r37-c1-ubizp (cod-a): single-source shortest PATHS over a MultiGraph's
/// adjacency directly (no simple-Graph build). Keep the BFS in node-index space:
/// store one predecessor per discovered node and let the Python emitter stream
/// path reconstruction from that parent table. This avoids cloning every
/// parent's path for every child and skips String materialization in the kernel.
fn multigraph_sssp_predecessors_index<'a>(
    mg: &'a fnx_classes::MultiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> (Vec<&'a str>, Option<usize>, Vec<usize>, Vec<usize>) {
    let nodes = mg.nodes_ordered();
    let node_indices: rustc_hash::FxHashMap<&'a str, usize> = nodes
        .iter()
        .copied()
        .enumerate()
        .map(|(idx, node)| (node, idx))
        .collect();
    let Some(&source_idx) = node_indices.get(source) else {
        return (nodes, None, Vec::new(), Vec::new());
    };

    let n = nodes.len();
    let mut seen = vec![false; n];
    let mut predecessor = vec![usize::MAX; n];
    let mut discovery = Vec::with_capacity(n);
    let mut frontier = vec![source_idx];
    let mut next = Vec::new();
    let mut depth = 0usize;

    seen[source_idx] = true;
    discovery.push(source_idx);

    while !frontier.is_empty() {
        if cutoff.is_some_and(|limit| depth >= limit) {
            break;
        }
        next.clear();
        for &node_idx in &frontier {
            let node = nodes[node_idx];
            let Some(nbrs) = mg.neighbors_iter(node) else {
                continue;
            };
            for v in nbrs {
                if let Some(&nbr_idx) = node_indices.get(v)
                    && !seen[nbr_idx]
                {
                    seen[nbr_idx] = true;
                    predecessor[nbr_idx] = node_idx;
                    discovery.push(nbr_idx);
                    next.push(nbr_idx);
                }
            }
        }
        std::mem::swap(&mut frontier, &mut next);
        depth += 1;
    }

    (nodes, Some(source_idx), discovery, predecessor)
}

/// MultiDiGraph sibling of `multigraph_sssp_predecessors_index`.
///
/// Unweighted shortest paths are multiplicity-invariant, but discovery order is
/// not. `MultiDiGraph::csr()` is revision-cached and preserves each successor
/// row's `G.succ[u]` insertion order while collapsing parallel edges, so the BFS
/// can stay in index space without a per-node row lookup or per-neighbor hash
/// lookup. That keeps NetworkX's parent/tie-break order and avoids the old
/// simple-DiGraph projection/String path rebuild.
fn multidigraph_sssp_predecessors_index<'a>(
    mdg: &'a fnx_classes::digraph::MultiDiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> (Vec<&'a str>, Option<usize>, Vec<usize>, Vec<usize>) {
    let nodes = mdg.nodes_ordered();
    let Some(source_idx) = nodes.iter().position(|&node| node == source) else {
        return (nodes, None, Vec::new(), Vec::new());
    };

    let n = nodes.len();
    let csr = mdg.csr();
    let mut seen = vec![false; n];
    let mut predecessor = vec![usize::MAX; n];
    let mut discovery = Vec::with_capacity(n);
    let mut frontier = vec![source_idx];
    let mut next = Vec::new();
    let mut depth = 0usize;

    seen[source_idx] = true;
    discovery.push(source_idx);

    while !frontier.is_empty() {
        if cutoff.is_some_and(|limit| depth >= limit) {
            break;
        }
        next.clear();
        for &node_idx in &frontier {
            for &successor in csr.successors(node_idx) {
                let successor_idx = successor as usize;
                if successor_idx < n && !seen[successor_idx] {
                    seen[successor_idx] = true;
                    predecessor[successor_idx] = node_idx;
                    discovery.push(successor_idx);
                    next.push(successor_idx);
                }
            }
        }
        std::mem::swap(&mut frontier, &mut next);
        depth += 1;
    }

    (nodes, Some(source_idx), discovery, predecessor)
}

fn emit_paths_dict_discovery_parent_index(
    py: Python<'_>,
    gr: &GraphRef<'_>,
    nodes: &[&str],
    source_idx: usize,
    source_obj: PyObject,
    discovery: &[usize],
    predecessor: &[usize],
) -> PyResult<pyo3::Py<PyDict>> {
    let mut disp: Vec<Option<PyObject>> =
        std::iter::repeat_with(|| None).take(nodes.len()).collect();
    disp[source_idx] = Some(source_obj);
    for &node_idx in discovery {
        if node_idx != source_idx {
            let parent_idx = predecessor[node_idx];
            disp[node_idx] = Some(gr.py_row_key(py, nodes[parent_idx], nodes[node_idx]));
        }
    }

    let dict = PyDict::new(py);
    let mut stack = Vec::new();
    for &node_idx in discovery {
        stack.clear();
        let mut current = node_idx;
        loop {
            stack.push(current);
            if current == source_idx {
                break;
            }
            current = predecessor[current];
        }
        let py_path = PyList::new(
            py,
            stack.iter().rev().map(|&idx| match &disp[idx] {
                Some(obj) => obj.clone_ref(py),
                None => gr.py_node_key(py, nodes[idx]),
            }),
        )?;
        let key = match &disp[node_idx] {
            Some(obj) => obj.clone_ref(py),
            None => gr.py_node_key(py, nodes[node_idx]),
        };
        dict.set_item(key, py_path)?;
    }
    Ok(dict.unbind())
}

fn emit_paths_dict_uniform_parent_index(
    py: Python<'_>,
    gr: &GraphRef<'_>,
    nodes: &[&str],
    source_idx: usize,
    source_obj: PyObject,
    discovery: &[usize],
    predecessor: &[usize],
) -> PyResult<pyo3::Py<PyDict>> {
    let mut py_nodes: Vec<PyObject> = nodes.iter().map(|node| gr.py_node_key(py, node)).collect();
    py_nodes[source_idx] = source_obj;

    let dict = PyDict::new(py);
    let mut path_cache: Vec<Option<Py<PyList>>> =
        std::iter::repeat_with(|| None).take(nodes.len()).collect();
    for &node_idx in discovery {
        let py_path = if node_idx == source_idx {
            PyList::new(py, [py_nodes[source_idx].clone_ref(py)])?
        } else {
            let parent_idx = predecessor[node_idx];
            let Some(parent_path) = path_cache.get(parent_idx).and_then(Option::as_ref) else {
                return Err(PyRuntimeError::new_err(
                    "single_source_shortest_path parent path missing",
                ));
            };
            let copied = parent_path
                .bind(py)
                .call_method0("copy")?
                .downcast_into::<PyList>()?;
            copied.append(py_nodes[node_idx].clone_ref(py))?;
            copied
        };
        dict.set_item(py_nodes[node_idx].clone_ref(py), &py_path)?;
        path_cache[node_idx] = Some(py_path.unbind());
    }
    Ok(dict.unbind())
}

fn emit_dijkstra_indexed_full(
    py: Python<'_>,
    gr: &GraphRef<'_>,
    nodes: &[&str],
    result: &fnx_algorithms::IndexedDijkstraFull,
    source_obj: PyObject,
) -> PyResult<(PyObject, PyObject)> {
    let mut disp: Vec<Option<PyObject>> =
        std::iter::repeat_with(|| None).take(nodes.len()).collect();
    disp[result.source_idx] = Some(source_obj);
    for &node in &result.finalize_order {
        let node_idx = node as usize;
        if node_idx == result.source_idx {
            continue;
        }
        let pred = result.predecessors[node_idx];
        if pred != u32::MAX {
            let pred_idx = pred as usize;
            disp[node_idx] = Some(gr.py_row_key(py, nodes[pred_idx], nodes[node_idx]));
        }
    }

    let dist_dict = PyDict::new(py);
    for &node in &result.finalize_order {
        let node_idx = node as usize;
        let key = match &disp[node_idx] {
            Some(obj) => obj.clone_ref(py),
            None => gr.py_node_key(py, nodes[node_idx]),
        };
        let distance = result.distances[node_idx];
        if result.all_int_paths[node_idx]
            && distance.is_finite()
            && distance.fract() == 0.0
            && distance >= i128::MIN as f64
            && distance <= i128::MAX as f64
        {
            dist_dict.set_item(key, PyInt::new(py, distance as i128))?;
        } else {
            dist_dict.set_item(key, distance)?;
        }
    }

    let path_dict = PyDict::new(py);
    let mut stack = Vec::new();
    for &node in &result.finalize_order {
        stack.clear();
        let mut current = node as usize;
        loop {
            stack.push(current);
            if current == result.source_idx {
                break;
            }
            let pred = result.predecessors[current];
            if pred == u32::MAX {
                break;
            }
            current = pred as usize;
        }
        let py_path: Vec<PyObject> = stack
            .iter()
            .rev()
            .map(|&idx| match &disp[idx] {
                Some(obj) => obj.clone_ref(py),
                None => gr.py_node_key(py, nodes[idx]),
            })
            .collect();
        let key = match &disp[node as usize] {
            Some(obj) => obj.clone_ref(py),
            None => gr.py_node_key(py, nodes[node as usize]),
        };
        path_dict.set_item(key, py_path)?;
    }

    Ok((dist_dict.into_any().unbind(), path_dict.into_any().unbind()))
}

/// br-r37-c1-ddw4l: unweighted single-pair distance over a MultiGraph by a
/// two-fringe BFS over the adjacency (no simple-Graph build). Expanding the
/// smaller frontier preserves level-BFS distances while avoiding the nearly
/// whole-graph scan paid by the old source-only search on sparse expanders.
/// Distance is multiplicity-invariant. Returns `Some(distance)` or `None` if
/// the target is unreachable.
fn multigraph_target_bfs_distance(
    mg: &fnx_classes::MultiGraph,
    source: &str,
    target: &str,
) -> Option<usize> {
    use std::collections::HashMap;

    if source == target {
        return Some(0);
    }
    let source = mg
        .get_node_index(source)
        .and_then(|index| mg.get_node_name(index))?;
    let target = mg
        .get_node_index(target)
        .and_then(|index| mg.get_node_name(index))?;

    let mut forward_distances = HashMap::from([(source, 0usize)]);
    let mut reverse_distances = HashMap::from([(target, 0usize)]);
    let mut forward_frontier = vec![source];
    let mut reverse_frontier = vec![target];

    while !forward_frontier.is_empty() && !reverse_frontier.is_empty() {
        if forward_frontier.len() <= reverse_frontier.len() {
            let mut next_frontier = Vec::new();
            for node in std::mem::take(&mut forward_frontier) {
                let next_distance = forward_distances[node] + 1;
                for neighbor in mg.neighbors(node).unwrap_or_default() {
                    if let Some(&reverse_distance) = reverse_distances.get(neighbor) {
                        return Some(next_distance + reverse_distance);
                    }
                    if !forward_distances.contains_key(neighbor) {
                        forward_distances.insert(neighbor, next_distance);
                        next_frontier.push(neighbor);
                    }
                }
            }
            forward_frontier = next_frontier;
        } else {
            let mut next_frontier = Vec::new();
            for node in std::mem::take(&mut reverse_frontier) {
                let next_distance = reverse_distances[node] + 1;
                for neighbor in mg.neighbors(node).unwrap_or_default() {
                    if let Some(&forward_distance) = forward_distances.get(neighbor) {
                        return Some(next_distance + forward_distance);
                    }
                    if !reverse_distances.contains_key(neighbor) {
                        reverse_distances.insert(neighbor, next_distance);
                        next_frontier.push(neighbor);
                    }
                }
            }
            reverse_frontier = next_frontier;
        }
    }

    None
}

/// `br-r37-c1-ddw4l` A/B baseline: the source-only target-early-exit BFS that
/// preceded the two-fringe search. Test-only so the benchmark compares both
/// algorithms in one release binary.
#[cfg(test)]
fn multigraph_target_bfs_distance_orig_unidirectional(
    mg: &fnx_classes::MultiGraph,
    source: &str,
    target: &str,
) -> Option<usize> {
    use std::collections::{HashSet, VecDeque};
    if source == target {
        return Some(0);
    }
    let mut visited: HashSet<&str> = HashSet::new();
    let mut queue: VecDeque<(&str, usize)> = VecDeque::new();
    if let Some(neighbors) = mg.neighbors(source) {
        for neighbor in neighbors {
            if neighbor == target {
                return Some(1);
            }
            if neighbor != source && visited.insert(neighbor) {
                queue.push_back((neighbor, 1));
            }
        }
    }
    while let Some((node, distance)) = queue.pop_front() {
        if let Some(neighbors) = mg.neighbors(node) {
            for neighbor in neighbors {
                if neighbor == target {
                    return Some(distance + 1);
                }
                if neighbor != source && visited.insert(neighbor) {
                    queue.push_back((neighbor, distance + 1));
                }
            }
        }
    }
    None
}

/// br-r37-c1-zid1b (cc): single-source BFS distances + discovery parents over a
/// MultiDiGraph's successor adjacency directly (no simple-DiGraph build). Mirrors the
/// MultiGraph helper using successors() for the forward direction. Distance is
/// multiplicity-invariant; processing successors in order matches nx's discovery.
fn multidigraph_sssp_length_with_parents<'a>(
    mdg: &'a fnx_classes::digraph::MultiDiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> Vec<(&'a str, usize, Option<&'a str>)> {
    use std::collections::VecDeque;
    // br-r37-c1-zid1b straggler (cc): BFS over the revision-cached integer CSR successor rows
    // (`mdg.csr()`) with a `Vec<bool>` mark array + integer queue, instead of a fresh
    // `mdg.successors(node)` `Vec<&str>` per pop + `HashSet<&str>` (String hashing) — mirrors
    // the sibling `multidigraph_weak_components_indexed`/`..._is_weakly_connected`. `build_csr`
    // fills `succ_targets` from `successors[node].keys()` (distinct successors, adjacency-row
    // order) mapped to indices — exactly what `mdg.successors(node)` yields — so BFS discovery
    // order (every (node, length, parent) tuple) is byte-identical; indices map back at the end.
    let nodes = mdg.nodes_ordered();
    let Some(source_idx) = nodes.iter().position(|&n| n == source) else {
        return Vec::new();
    };
    let n = nodes.len();
    let csr = mdg.csr();
    let discovered: Vec<(usize, usize, Option<usize>)> = {
        let mut visited = vec![false; n];
        let mut disc: Vec<(usize, usize, Option<usize>)> = Vec::new();
        visited[source_idx] = true;
        disc.push((source_idx, 0, None));
        let mut queue: VecDeque<(usize, usize)> = VecDeque::new();
        queue.push_back((source_idx, 0));
        while let Some((node, dist)) = queue.pop_front() {
            if let Some(c) = cutoff
                && dist >= c
            {
                continue;
            }
            for &target in csr.successors(node) {
                let v = target as usize;
                if v < n && !visited[v] {
                    visited[v] = true;
                    disc.push((v, dist + 1, Some(node)));
                    queue.push_back((v, dist + 1));
                }
            }
        }
        disc
    };
    discovered
        .into_iter()
        .map(|(ni, d, pi)| (nodes[ni], d, pi.map(|p| nodes[p])))
        .collect()
}

/// br-r37-c1-zid1b straggler A/B baseline: the pre-lever `multidigraph_sssp_length_with_parents`
/// (fresh `mdg.successors(node)` `Vec<&str>` per pop + `HashSet<&str>` visited). Test-only;
/// byte-identical to the CSR version.
#[cfg(test)]
fn multidigraph_sssp_length_with_parents_orig_string<'a>(
    mdg: &'a fnx_classes::digraph::MultiDiGraph,
    source: &str,
    cutoff: Option<usize>,
) -> Vec<(&'a str, usize, Option<&'a str>)> {
    use std::collections::{HashSet, VecDeque};
    let mut out: Vec<(&'a str, usize, Option<&'a str>)> = Vec::new();
    let nodes = mdg.nodes_ordered();
    let source_ref: &'a str = match nodes.iter().copied().find(|&n| n == source) {
        Some(s) => s,
        None => return out,
    };
    let mut visited: HashSet<&'a str> = HashSet::new();
    visited.insert(source_ref);
    out.push((source_ref, 0, None));
    let mut queue: VecDeque<(&'a str, usize)> = VecDeque::new();
    queue.push_back((source_ref, 0));
    while let Some((node, dist)) = queue.pop_front() {
        if let Some(c) = cutoff
            && dist >= c
        {
            continue;
        }
        if let Some(succs) = mdg.successors(node) {
            for v in succs {
                if visited.insert(v) {
                    out.push((v, dist + 1, Some(node)));
                    queue.push_back((v, dist + 1));
                }
            }
        }
    }
    out
}

/// br-r37-c1-04z53.9166: weakly-connected components of a MultiDiGraph by
/// direct BFS over revision-cached CSR rows.
fn multidigraph_weak_components_indexed<'a>(
    mdg: &'a fnx_classes::digraph::MultiDiGraph,
) -> Vec<Vec<&'a str>> {
    use std::collections::VecDeque;
    let nodes = mdg.nodes_ordered();
    let n = nodes.len();
    let csr = mdg.csr();
    let mut visited = vec![false; n];
    let mut components: Vec<Vec<&'a str>> = Vec::new();
    for start_idx in 0..n {
        if visited[start_idx] {
            continue;
        }
        visited[start_idx] = true;
        let mut comp: Vec<&'a str> = vec![nodes[start_idx]];
        let mut queue: VecDeque<usize> = VecDeque::new();
        queue.push_back(start_idx);
        while let Some(node_idx) = queue.pop_front() {
            for &target in csr.successors(node_idx) {
                let target_idx = target as usize;
                if target_idx < n && !visited[target_idx] {
                    visited[target_idx] = true;
                    comp.push(nodes[target_idx]);
                    queue.push_back(target_idx);
                }
            }
            for &source in csr.predecessors(node_idx) {
                let source_idx = source as usize;
                if source_idx < n && !visited[source_idx] {
                    visited[source_idx] = true;
                    comp.push(nodes[source_idx]);
                    queue.push_back(source_idx);
                }
            }
        }
        components.push(comp);
    }
    components
}

/// br-r37-c1-04z53.9166: is a MultiDiGraph weakly connected? Early-exit BFS
/// over the same cached CSR rows used for component enumeration.
fn multidigraph_is_weakly_connected(mdg: &fnx_classes::digraph::MultiDiGraph) -> bool {
    use std::collections::VecDeque;
    let nodes = mdg.nodes_ordered();
    let n = nodes.len();
    if n == 0 {
        return true;
    }
    let csr = mdg.csr();
    let mut visited = vec![false; n];
    visited[0] = true;
    let mut visited_count = 1usize;
    let mut queue: VecDeque<usize> = VecDeque::new();
    queue.push_back(0);
    while let Some(node_idx) = queue.pop_front() {
        for &target in csr.successors(node_idx) {
            let target_idx = target as usize;
            if target_idx < n && !visited[target_idx] {
                visited[target_idx] = true;
                visited_count += 1;
                if visited_count == n {
                    return true;
                }
                queue.push_back(target_idx);
            }
        }
        for &source in csr.predecessors(node_idx) {
            let source_idx = source as usize;
            if source_idx < n && !visited[source_idx] {
                visited[source_idx] = true;
                visited_count += 1;
                if visited_count == n {
                    return true;
                }
                queue.push_back(source_idx);
            }
        }
    }
    visited_count == n
}

/// Count MultiDiGraph weak components via the same CSR-backed undirected walk
/// without materializing component vectors.
fn multidigraph_number_weakly_connected_components(
    mdg: &fnx_classes::digraph::MultiDiGraph,
) -> usize {
    use std::collections::VecDeque;
    let n = mdg.node_count();
    if n == 0 {
        return 0;
    }
    let csr = mdg.csr();
    let mut visited = vec![false; n];
    let mut components = 0usize;
    let mut queue: VecDeque<usize> = VecDeque::new();
    for start_idx in 0..n {
        if visited[start_idx] {
            continue;
        }
        components += 1;
        visited[start_idx] = true;
        queue.push_back(start_idx);
        while let Some(node_idx) = queue.pop_front() {
            for &target in csr.successors(node_idx) {
                let target_idx = target as usize;
                if target_idx < n && !visited[target_idx] {
                    visited[target_idx] = true;
                    queue.push_back(target_idx);
                }
            }
            for &source in csr.predecessors(node_idx) {
                let source_idx = source as usize;
                if source_idx < n && !visited[source_idx] {
                    visited[source_idx] = true;
                    queue.push_back(source_idx);
                }
            }
        }
    }
    components
}

/// br-r37-c1-zid1b (cc): unweighted single-pair directed distance over a MultiDiGraph
/// by a target-early-exit BFS over the SUCCESSOR adjacency (no simple-DiGraph build),
/// O(1) source seeding. Multiplicity-invariant. Some(distance) or None if unreachable.
fn multidigraph_target_bfs_distance(
    mdg: &fnx_classes::digraph::MultiDiGraph,
    source: &str,
    target: &str,
) -> Option<usize> {
    use std::collections::VecDeque;
    if source == target {
        return Some(0);
    }
    let mut visited: rustc_hash::FxHashSet<&str> = rustc_hash::FxHashSet::default();
    let mut queue: VecDeque<(&str, usize)> = VecDeque::new();
    if let Some(succs) = mdg.successors_iter(source) {
        for v in succs {
            if v == target {
                return Some(1);
            }
            if v != source && visited.insert(v) {
                queue.push_back((v, 1));
            }
        }
    }
    while let Some((node, dist)) = queue.pop_front() {
        if let Some(succs) = mdg.successors_iter(node) {
            for v in succs {
                if v == target {
                    return Some(dist + 1);
                }
                if v != source && visited.insert(v) {
                    queue.push_back((v, dist + 1));
                }
            }
        }
    }
    None
}

/// br-r37-c1-1pmou: boolean MultiDiGraph strong-connectivity test using a lazy
/// Tarjan walk. Multiplicity is irrelevant, so successor rows are traversed as
/// distinct neighbor rows and the function returns false as soon as it closes
/// any SCC smaller than the graph. This matches nx's order-invariant boolean
/// contract while avoiding full successor+predecessor CSR materialization for
/// the common not-strongly-connected case.
fn multidigraph_is_strongly_connected(mdg: &fnx_classes::digraph::MultiDiGraph) -> bool {
    // br-r37-c1-d291d (cc): run the iterative Tarjan over the pre-existing
    // revision-keyed integer CSR successor rows instead of rebuilding an inline
    // `HashMap<&str,usize>` + per-node `successors()` String Vec each call. The CSR
    // rows are the same distinct successors in the same order (already node indices),
    // so the preorder/lowlink DFS is byte-identical → identical strong-connectivity
    // bool. Wins warm (cache) and cold (flat CSR build < HashMap/String rebuild).
    let n = mdg.node_count();
    if n == 0 {
        return true;
    }
    let csr = mdg.csr();
    let mut preorder = vec![0usize; n];
    let mut lowlink = vec![0usize; n];
    let mut scc_found = vec![false; n];
    let mut scc_queue = Vec::<usize>::new();
    let mut preorder_counter = 0usize;

    for source in 0..n {
        if scc_found[source] {
            continue;
        }
        let mut queue: Vec<(usize, &[u32], usize)> = vec![(source, csr.successors(source), 0)];
        while let Some((v_ref, successors, next_successor)) = queue.last_mut() {
            let v = *v_ref;
            if preorder[v] == 0 {
                preorder_counter += 1;
                preorder[v] = preorder_counter;
            }

            let mut descended = false;
            while *next_successor < successors.len() {
                let w = successors[*next_successor] as usize;
                *next_successor += 1;
                if w < n && preorder[w] == 0 {
                    queue.push((w, csr.successors(w), 0));
                    descended = true;
                    break;
                }
            }
            if descended {
                continue;
            }

            lowlink[v] = preorder[v];
            for &raw in csr.successors(v) {
                let w = raw as usize;
                if w >= n || scc_found[w] {
                    continue;
                }
                if preorder[w] > preorder[v] {
                    lowlink[v] = lowlink[v].min(lowlink[w]);
                } else {
                    lowlink[v] = lowlink[v].min(preorder[w]);
                }
            }

            queue.pop();
            if lowlink[v] == preorder[v] {
                let mut component_size = 1usize;
                while scc_queue
                    .last()
                    .is_some_and(|&queued| preorder[queued] > preorder[v])
                {
                    let Some(queued) = scc_queue.pop() else {
                        break;
                    };
                    scc_found[queued] = true;
                    component_size += 1;
                }
                scc_found[v] = true;
                return component_size == n;
            }
            scc_queue.push(v);
        }
    }

    false
}

