/// Return whether the given nodes form a dominating set.
#[pyfunction]
pub fn is_dominating_set(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    nbunch: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let gr = extract_graph(g)?;
    require_undirected(&gr, "is_dominating_set")?;
    let inner = gr.undirected();
    let nodes: Vec<String> = nbunch
        .try_iter()?
        .map(|item| node_key_to_string(py, &item?))
        .collect::<PyResult<Vec<_>>>()?;
    let refs: Vec<&str> = nodes.iter().map(String::as_str).collect();
    Ok(py.allow_threads(|| fnx_algorithms::is_dominating_set(inner, &refs)))
}

// ===========================================================================
// Strongly Connected Components
// ===========================================================================

/// Return the strongly connected components of a directed graph.
#[pyfunction]
pub fn strongly_connected_components(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
) -> PyResult<Vec<PyObject>> {
    let gr = extract_graph(g)?;
    if !gr.is_directed() {
        return Err(crate::NetworkXNotImplemented::new_err(
            "strongly_connected_components is not defined for undirected graphs. Use connected_components instead.",
        ));
    }
    if let GraphRef::MultiDirected { mdg, .. } = &gr {
        // br-r37-c1-zid1b: SCC listing is multiplicity-invariant, so walk the
        // MultiDiGraph successor rows directly instead of first projecting to a
        // simple DiGraph.
        let inner = &mdg.inner;
        let nodes = inner.nodes_ordered();
        let result = py
            .allow_threads(|| multidigraph_strongly_connected_component_indices_nx_ordered(inner));
        return result
            .iter()
            .map(|comp| {
                let py_nodes: Vec<PyObject> = comp
                    .iter()
                    .map(|&node_idx| gr.py_node_key(py, nodes[node_idx]))
                    .collect();
                pyo3::types::PySet::new(py, py_nodes).map(|set| set.into_any().unbind())
            })
            .collect();
    }
    let dg_ref = gr.digraph().expect("is_directed checked above");
    let result = py.allow_threads(|| strongly_connected_components_nx_ordered(dg_ref));
    result
        .iter()
        .map(|comp| {
            let py_nodes: Vec<PyObject> =
                comp.iter().map(|node| gr.py_node_key(py, node)).collect();
            pyo3::types::PySet::new(py, py_nodes).map(|set| set.into_any().unbind())
        })
        .collect()
}

/// Reachability of every node from `source` over the DiGraph's native integer
/// successor (or predecessor, when `reverse`) rows. Order-invariant boolean used
/// for the single-SCC fast path — no adjacency rebuild.
fn digraph_reaches_every_node(
    digraph: &fnx_classes::digraph::DiGraph,
    source: usize,
    n: usize,
    reverse: bool,
) -> bool {
    let mut visited = vec![false; n];
    let mut stack = vec![source];
    visited[source] = true;
    let mut seen = 1usize;
    while let Some(node) = stack.pop() {
        let neighbors = if reverse {
            digraph.predecessors_indices(node)
        } else {
            digraph.successors_indices(node)
        };
        if let Some(neighbors) = neighbors {
            for &neighbor in neighbors {
                if !visited[neighbor] {
                    visited[neighbor] = true;
                    seen += 1;
                    stack.push(neighbor);
                }
            }
        }
    }
    seen == n
}

fn strongly_connected_components_nx_ordered(
    digraph: &fnx_classes::digraph::DiGraph,
) -> Vec<Vec<String>> {
    // br-r37-c1-rjj10 (cc): walk the DiGraph's native integer successor rows
    // (`successors_indices(idx) -> &[usize]`) directly instead of rebuilding an
    // inline `HashMap<&str,usize>` + successors/predecessors `Vec<Vec<usize>>` via
    // `successors_iter` — the former path round-trips int→name→int (name yield +
    // per-neighbour hash lookup) every call. The native rows are the same distinct
    // successors in the same order, so the preorder/lowlink Tarjan and the emitted
    // component partition/order are byte-identical. Rows are always live (no memo),
    // so this wins uniformly, not just warm.
    let nodes = digraph.nodes_ordered();
    let n = nodes.len();
    if n == 0 {
        return Vec::new();
    }
    if digraph_reaches_every_node(digraph, 0, n, false)
        && digraph_reaches_every_node(digraph, 0, n, true)
    {
        return vec![nodes.into_iter().map(str::to_owned).collect()];
    }

    let mut preorder = vec![0usize; n];
    let mut lowlink = vec![0usize; n];
    let mut scc_found = vec![false; n];
    let mut scc_queue = Vec::<usize>::new();
    let mut neighbor_pos = vec![0usize; n];
    let mut preorder_counter = 0usize;
    let mut result = Vec::new();

    for source in 0..n {
        if scc_found[source] {
            continue;
        }
        let mut queue = vec![source];
        while let Some(&v) = queue.last() {
            if preorder[v] == 0 {
                preorder_counter += 1;
                preorder[v] = preorder_counter;
            }
            let succ_v = digraph.successors_indices(v).unwrap_or(&[]);

            let mut done = true;
            while neighbor_pos[v] < succ_v.len() {
                let w = succ_v[neighbor_pos[v]];
                neighbor_pos[v] += 1;
                if preorder[w] == 0 {
                    queue.push(w);
                    done = false;
                    break;
                }
            }

            if done {
                lowlink[v] = preorder[v];
                for &w in succ_v {
                    if !scc_found[w] {
                        if preorder[w] > preorder[v] {
                            lowlink[v] = lowlink[v].min(lowlink[w]);
                        } else {
                            lowlink[v] = lowlink[v].min(preorder[w]);
                        }
                    }
                }
                queue.pop();
                if lowlink[v] == preorder[v] {
                    let mut component_indices = vec![v];
                    while scc_queue
                        .last()
                        .is_some_and(|&queued| preorder[queued] > preorder[v])
                    {
                        if let Some(queued) = scc_queue.pop() {
                            component_indices.push(queued);
                        }
                    }
                    for &idx in &component_indices {
                        scc_found[idx] = true;
                    }
                    let component = component_indices
                        .into_iter()
                        .map(|idx| nodes[idx].to_owned())
                        .collect();
                    result.push(component);
                } else {
                    scc_queue.push(v);
                }
            }
        }
    }

    result
}

/// Frozen pre-`br-r37-c1-rjj10` inline-`HashMap` Tarjan route — rebuilds the
/// name→index map and successor/predecessor adjacency via `successors_iter` each
/// call. Kept for the same-binary A/B and exact-order parity proof.
#[cfg(test)]
fn strongly_connected_components_nx_ordered_orig_inline(
    digraph: &fnx_classes::digraph::DiGraph,
) -> Vec<Vec<String>> {
    let nodes = digraph.nodes_ordered();
    let node_indices: HashMap<&str, usize> = nodes
        .iter()
        .copied()
        .enumerate()
        .map(|(index, node)| (node, index))
        .collect();
    let mut predecessors = vec![Vec::<usize>::new(); nodes.len()];
    let successors: Vec<Vec<usize>> = nodes
        .iter()
        .enumerate()
        .map(|(index, &node)| {
            digraph.successors_iter(node).map_or_else(Vec::new, |iter| {
                iter.filter_map(|succ| {
                    let succ_index = node_indices.get(succ).copied()?;
                    predecessors[succ_index].push(index);
                    Some(succ_index)
                })
                .collect()
            })
        })
        .collect();

    if nodes.is_empty() {
        return Vec::new();
    }
    if reaches_every_node(0, &successors) && reaches_every_node(0, &predecessors) {
        return vec![nodes.into_iter().map(str::to_owned).collect()];
    }

    let mut preorder = vec![0usize; nodes.len()];
    let mut lowlink = vec![0usize; nodes.len()];
    let mut scc_found = vec![false; nodes.len()];
    let mut scc_queue = Vec::<usize>::new();
    let mut neighbor_pos = vec![0usize; nodes.len()];
    let mut preorder_counter = 0usize;
    let mut result = Vec::new();

    for source in 0..nodes.len() {
        if scc_found[source] {
            continue;
        }
        let mut queue = vec![source];
        while let Some(&v) = queue.last() {
            if preorder[v] == 0 {
                preorder_counter += 1;
                preorder[v] = preorder_counter;
            }

            let mut done = true;
            while neighbor_pos[v] < successors[v].len() {
                let w = successors[v][neighbor_pos[v]];
                neighbor_pos[v] += 1;
                if preorder[w] == 0 {
                    queue.push(w);
                    done = false;
                    break;
                }
            }

            if done {
                lowlink[v] = preorder[v];
                for &w in &successors[v] {
                    if !scc_found[w] {
                        if preorder[w] > preorder[v] {
                            lowlink[v] = lowlink[v].min(lowlink[w]);
                        } else {
                            lowlink[v] = lowlink[v].min(preorder[w]);
                        }
                    }
                }
                queue.pop();
                if lowlink[v] == preorder[v] {
                    let mut component_indices = vec![v];
                    while scc_queue
                        .last()
                        .is_some_and(|&queued| preorder[queued] > preorder[v])
                    {
                        if let Some(queued) = scc_queue.pop() {
                            component_indices.push(queued);
                        }
                    }
                    for &idx in &component_indices {
                        scc_found[idx] = true;
                    }
                    let component = component_indices
                        .into_iter()
                        .map(|idx| nodes[idx].to_owned())
                        .collect();
                    result.push(component);
                } else {
                    scc_queue.push(v);
                }
            }
        }
    }

    result
}

fn multidigraph_strongly_connected_component_indices_nx_ordered(
    mdg: &fnx_classes::digraph::MultiDiGraph,
) -> Vec<Vec<usize>> {
    let n = mdg.node_count();
    if n == 0 {
        return Vec::new();
    }

    let csr = mdg.csr();
    if multidigraph_csr_reaches_every_node(&csr, 0, n, false)
        && multidigraph_csr_reaches_every_node(&csr, 0, n, true)
    {
        return vec![(0..n).collect()];
    }

    let mut preorder = vec![0usize; n];
    let mut lowlink = vec![0usize; n];
    let mut scc_found = vec![false; n];
    let mut scc_queue = Vec::<usize>::new();
    let mut neighbor_pos = vec![0usize; n];
    let mut preorder_counter = 0usize;
    let mut result = Vec::new();

    for source in 0..n {
        if scc_found[source] {
            continue;
        }
        let mut queue = vec![source];
        while let Some(&v) = queue.last() {
            if preorder[v] == 0 {
                preorder_counter += 1;
                preorder[v] = preorder_counter;
            }

            let neighbors = csr.successors(v);
            let mut done = true;
            while neighbor_pos[v] < neighbors.len() {
                let w = neighbors[neighbor_pos[v]] as usize;
                neighbor_pos[v] += 1;
                if preorder[w] == 0 {
                    queue.push(w);
                    done = false;
                    break;
                }
            }

            if done {
                lowlink[v] = preorder[v];
                for &raw_w in csr.successors(v) {
                    let w = raw_w as usize;
                    if !scc_found[w] {
                        if preorder[w] > preorder[v] {
                            lowlink[v] = lowlink[v].min(lowlink[w]);
                        } else {
                            lowlink[v] = lowlink[v].min(preorder[w]);
                        }
                    }
                }
                queue.pop();
                if lowlink[v] == preorder[v] {
                    let mut component_indices = vec![v];
                    while scc_queue
                        .last()
                        .is_some_and(|&queued| preorder[queued] > preorder[v])
                    {
                        if let Some(queued) = scc_queue.pop() {
                            component_indices.push(queued);
                        }
                    }
                    for &idx in &component_indices {
                        scc_found[idx] = true;
                    }
                    result.push(component_indices);
                } else {
                    scc_queue.push(v);
                }
            }
        }
    }

    result
}

fn multidigraph_csr_reaches_every_node(
    csr: &fnx_classes::digraph::MultiDiCsr,
    source: usize,
    n: usize,
    reverse: bool,
) -> bool {
    let mut visited = vec![false; n];
    let mut stack = vec![source];
    visited[source] = true;
    let mut seen = 1usize;

    while let Some(node) = stack.pop() {
        let neighbors = if reverse {
            csr.predecessors(node)
        } else {
            csr.successors(node)
        };
        for &raw_neighbor in neighbors {
            let neighbor = raw_neighbor as usize;
            if !visited[neighbor] {
                visited[neighbor] = true;
                seen += 1;
                stack.push(neighbor);
            }
        }
    }

    seen == n
}

fn multidigraph_strongly_connected_components_nx_ordered(
    mdg: &fnx_classes::digraph::MultiDiGraph,
) -> Vec<Vec<String>> {
    // br-r37-c1-vrbmf (cc): the sibling `_indices_` variant already runs this EXACT
    // Tarjan (identical preorder/lowlink/scc_queue, single-SCC fast path, component
    // collection order) over the cached `mdg.csr()`. Delegate to it and map the
    // component indices to names instead of rebuilding a duplicate inline
    // `HashMap<&str,usize>` + per-node `successors()` String adjacency. Byte-identical
    // component partition AND order (csr.successors == mdg.successors key order; the
    // (0..n) single-SCC fast path equals the node-insertion order); wins warm (cache)
    // and cold (flat CSR build < HashMap/String rebuild) — same as number_scc (giqjb).
    let nodes = mdg.nodes_ordered();
    multidigraph_strongly_connected_component_indices_nx_ordered(mdg)
        .into_iter()
        .map(|component| {
            component
                .into_iter()
                .map(|idx| nodes[idx].to_owned())
                .collect()
        })
        .collect()
}

/// Frozen pre-`br-r37-c1-vrbmf` inline-`HashMap` Tarjan route — rebuilds the
/// name→index map and successor/predecessor adjacency each call. Kept for the
/// same-binary A/B and exact-order parity proof.
#[cfg(test)]
fn multidigraph_strongly_connected_components_nx_ordered_orig_inline(
    mdg: &fnx_classes::digraph::MultiDiGraph,
) -> Vec<Vec<String>> {
    let nodes = mdg.nodes_ordered();
    let node_indices: HashMap<&str, usize> = nodes
        .iter()
        .copied()
        .enumerate()
        .map(|(index, node)| (node, index))
        .collect();
    let mut predecessors = vec![Vec::<usize>::new(); nodes.len()];
    let successors: Vec<Vec<usize>> = nodes
        .iter()
        .enumerate()
        .map(|(index, &node)| {
            mdg.successors(node).map_or_else(Vec::new, |succs| {
                succs
                    .into_iter()
                    .filter_map(|succ| {
                        let succ_index = node_indices.get(succ).copied()?;
                        predecessors[succ_index].push(index);
                        Some(succ_index)
                    })
                    .collect()
            })
        })
        .collect();

    if nodes.is_empty() {
        return Vec::new();
    }
    if reaches_every_node(0, &successors) && reaches_every_node(0, &predecessors) {
        return vec![nodes.into_iter().map(str::to_owned).collect()];
    }

    let mut preorder = vec![0usize; nodes.len()];
    let mut lowlink = vec![0usize; nodes.len()];
    let mut scc_found = vec![false; nodes.len()];
    let mut scc_queue = Vec::<usize>::new();
    let mut neighbor_pos = vec![0usize; nodes.len()];
    let mut preorder_counter = 0usize;
    let mut result = Vec::new();

    for source in 0..nodes.len() {
        if scc_found[source] {
            continue;
        }
        let mut queue = vec![source];
        while let Some(&v) = queue.last() {
            if preorder[v] == 0 {
                preorder_counter += 1;
                preorder[v] = preorder_counter;
            }

            let mut done = true;
            while neighbor_pos[v] < successors[v].len() {
                let w = successors[v][neighbor_pos[v]];
                neighbor_pos[v] += 1;
                if preorder[w] == 0 {
                    queue.push(w);
                    done = false;
                    break;
                }
            }

            if done {
                lowlink[v] = preorder[v];
                for &w in &successors[v] {
                    if !scc_found[w] {
                        if preorder[w] > preorder[v] {
                            lowlink[v] = lowlink[v].min(lowlink[w]);
                        } else {
                            lowlink[v] = lowlink[v].min(preorder[w]);
                        }
                    }
                }
                queue.pop();
                if lowlink[v] == preorder[v] {
                    let mut component_indices = vec![v];
                    while scc_queue
                        .last()
                        .is_some_and(|&queued| preorder[queued] > preorder[v])
                    {
                        if let Some(queued) = scc_queue.pop() {
                            component_indices.push(queued);
                        }
                    }
                    for &idx in &component_indices {
                        scc_found[idx] = true;
                    }
                    let component = component_indices
                        .into_iter()
                        .map(|idx| nodes[idx].to_owned())
                        .collect();
                    result.push(component);
                } else {
                    scc_queue.push(v);
                }
            }
        }
    }

    result
}

fn reaches_every_node(source: usize, adjacency: &[Vec<usize>]) -> bool {
    let mut visited = vec![false; adjacency.len()];
    let mut stack = vec![source];
    visited[source] = true;
    let mut seen = 1usize;

    while let Some(node) = stack.pop() {
        for &neighbor in &adjacency[node] {
            if !visited[neighbor] {
                visited[neighbor] = true;
                seen += 1;
                stack.push(neighbor);
            }
        }
    }

    seen == adjacency.len()
}

/// Return the number of strongly connected components.
#[pyfunction]
pub fn number_strongly_connected_components(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
) -> PyResult<usize> {
    let gr = extract_graph(g)?;
    if !gr.is_directed() {
        return Err(crate::NetworkXNotImplemented::new_err(
            "number_strongly_connected_components is not defined for undirected graphs.",
        ));
    }
    if let GraphRef::MultiDirected { mdg, .. } = &gr {
        // br-r37-c1-11m92: Kosaraju SCC count over the multidigraph CSR, no conversion.
        let inner = &mdg.inner;
        return Ok(py.allow_threads(|| multidigraph_number_scc(inner)));
    }
    {
        let dg_ref = gr.digraph().expect("is_directed checked above");
        Ok(py.allow_threads(|| fnx_algorithms::number_strongly_connected_components(dg_ref)))
    }
}

/// Return whether the directed graph is strongly connected.
#[pyfunction]
pub fn is_strongly_connected(py: Python<'_>, g: &Bound<'_, PyAny>) -> PyResult<bool> {
    let gr = extract_graph(g)?;
    if !gr.is_directed() {
        return Err(crate::NetworkXNotImplemented::new_err(
            "is_strongly_connected is not defined for undirected graphs. Use is_connected instead.",
        ));
    }
    if let GraphRef::MultiDirected { mdg, .. } = &gr {
        // br-r37-c1-1pmou: direct boolean SCC over MultiDiGraph adjacency instead
        // of building a simple DiGraph or materializing forward+reverse CSR.
        let inner = &mdg.inner;
        if inner.node_count() == 0 {
            return Err(crate::NetworkXPointlessConcept::new_err(
                "Connectivity is undefined for the null graph.",
            ));
        }
        return Ok(py.allow_threads(|| multidigraph_is_strongly_connected(inner)));
    }
    {
        let dg_ref = gr.digraph().expect("is_directed checked above");
        if dg_ref.node_count() == 0 {
            return Err(crate::NetworkXPointlessConcept::new_err(
                "Connectivity is undefined for the null graph.",
            ));
        }
        Ok(py.allow_threads(|| strongly_connected_via_reachability(dg_ref)))
    }
}

/// br-r37-c1-04z53: a digraph is strongly connected iff, from any single
/// vertex, every vertex is reachable following edges FORWARD and every vertex
/// can reach it (i.e. is reachable following edges BACKWARD). Two index-space
/// traversals with early-exit on the forward pass — O(V+E), and bails on the
/// first pass for the common not-strongly-connected case. The previous kernel
/// (`number_strongly_connected_components == 1`) computed the FULL SCC
/// decomposition, labelling every component before counting, which was ~2x
/// slower than nx's `len(next(strongly_connected_components(G))) == len(G)`
/// (nx stops after the first, often size-1, SCC). Boolean output is
/// order-invariant, so this matches nx exactly. `node_count() > 0` is
/// guaranteed by the caller.
fn strongly_connected_via_reachability(dg: &fnx_classes::digraph::DiGraph) -> bool {
    let n = dg.node_count();
    let mut seen = vec![false; n];
    let mut stack: Vec<usize> = Vec::with_capacity(n);

    // Forward reachability from node 0; bail the instant it cannot reach all.
    seen[0] = true;
    stack.push(0);
    let mut count = 1usize;
    while let Some(u) = stack.pop() {
        if let Some(succs) = dg.successors_indices(u) {
            for &v in succs {
                if !seen[v] {
                    seen[v] = true;
                    count += 1;
                    stack.push(v);
                }
            }
        }
    }
    if count != n {
        return false;
    }

    // Backward reachability from node 0 (forward over the transpose).
    seen.fill(false);
    seen[0] = true;
    stack.push(0);
    count = 1;
    while let Some(u) = stack.pop() {
        if let Some(preds) = dg.predecessors_indices(u) {
            for &v in preds {
                if !seen[v] {
                    seen[v] = true;
                    count += 1;
                    stack.push(v);
                }
            }
        }
    }
    count == n
}

/// Condense a directed graph by contracting each SCC into a single node.
///
/// Returns a tuple (condensation_graph, mapping) where mapping is a dict
/// from original nodes to SCC indices.
#[pyfunction]
pub fn condensation(py: Python<'_>, g: &Bound<'_, PyAny>) -> PyResult<(PyObject, PyObject)> {
    let gr = extract_graph(g)?;
    if !gr.is_directed() {
        return Err(crate::NetworkXNotImplemented::new_err(
            "condensation is not defined for undirected graphs.",
        ));
    }
    {
        let dg_ref = gr.digraph().expect("is_directed checked above");
        let (cond_graph, node_mapping) = py.allow_threads(|| fnx_algorithms::condensation(dg_ref));
        // Build the condensation DiGraph
        let mut py_dg = PyDiGraph::new_empty_with_policy(py, dg_ref.runtime_policy().clone())?;
        for node in cond_graph.nodes_ordered() {
            py_dg.node_key_map.insert(
                node.to_owned(),
                node.parse::<i64>()
                    .expect("is_directed checked above")
                    .into_pyobject(py)?
                    .into_any()
                    .unbind(),
            );
            py_dg
                .node_py_attrs
                .insert(node.to_owned(), pyo3::types::PyDict::new(py).unbind());
            py_dg.inner.add_node(node);
        }
        for edge in cond_graph.edges_ordered() {
            let _ = py_dg.inner.add_edge(&edge.left, &edge.right);
            py_dg.edge_py_attrs.insert(
                (edge.left, edge.right),
                pyo3::types::PyDict::new(py).unbind(),
            );
        }
        let py_cond = py_dg.into_pyobject(py)?.into_any().unbind();
        // Build the mapping dict
        let mapping = pyo3::types::PyDict::new(py);
        for (node, scc_idx) in &node_mapping {
            mapping.set_item(gr.py_node_key(py, node), *scc_idx)?;
        }
        Ok((py_cond, mapping.into_any().unbind()))
    }
}

/// Build `condensation(G)` with NetworkX-compatible SCC labels in one native pass.
#[pyfunction]
pub fn condensation_nx_ordered(py: Python<'_>, g: &Bound<'_, PyAny>) -> PyResult<PyObject> {
    let gr = extract_graph(g)?;
    if !gr.is_directed() {
        return Err(crate::NetworkXNotImplemented::new_err(
            "condensation is not defined for undirected graphs.",
        ));
    }

    // br-r37-c1-condmdg: for a MultiDiGraph, gr.digraph() projects to a simple
    // DiGraph (multidigraph_to_simple_digraph) cloning every edge AttrMap — ~7x
    // nx. SCC and the cross-SCC edge set are multiplicity-invariant, so build the
    // condensation directly on the multidigraph's integer successor rows using
    // the native nx-ordered multidigraph SCC kernel. The (cu, cv) first-seen
    // dedup matches nx's `for u, v in G.edges()` (parallel edges collapse).
    if let GraphRef::MultiDirected { mdg, .. } = &gr {
        let inner = &mdg.inner;
        let nodes = inner.nodes_ordered();
        let node_indices: HashMap<&str, usize> = nodes
            .iter()
            .copied()
            .enumerate()
            .map(|(index, node)| (node, index))
            .collect();
        // Lightweight distinct-successor index adjacency — far cheaper than the
        // simple-DiGraph projection (no AttrMap clones, no String IndexMaps).
        let succ_adj: Vec<Vec<usize>> = nodes
            .iter()
            .map(|&node| {
                inner.successors(node).map_or_else(Vec::new, |succs| {
                    succs
                        .into_iter()
                        .filter_map(|s| node_indices.get(s).copied())
                        .collect()
                })
            })
            .collect();
        let components =
            py.allow_threads(|| multidigraph_strongly_connected_components_nx_ordered(inner));
        return build_condensation_py(
            py,
            &gr,
            components,
            inner.node_count(),
            inner.runtime_policy(),
            |node| node_indices.get(node).copied(),
            |u_idx| succ_adj.get(u_idx).map(Vec::as_slice),
        );
    }

    let dg_ref = gr.digraph().expect("is_directed checked above");
    let components = py.allow_threads(|| strongly_connected_components_nx_ordered(dg_ref));
    build_condensation_py(
        py,
        &gr,
        components,
        dg_ref.node_count(),
        dg_ref.runtime_policy(),
        |node| dg_ref.get_node_index(node),
        |u_idx| dg_ref.successors_indices(u_idx),
    )
}

/// br-r37-c1-condmdg: assemble the condensation PyDiGraph from nx-ordered SCC
/// components plus a node-index / successor-row view of the source graph. Shared
/// by the simple-DiGraph and direct-MultiDiGraph paths so neither pays a
/// simple-graph projection. `successors` rows are walked in source-major order
/// (nx's `for u, v in G.edges()`); `(cu, cv)` first-seen dedup yields a
/// byte-identical condensation DAG and edge order.
#[allow(clippy::too_many_arguments)]
fn build_condensation_py<'a>(
    py: Python<'_>,
    gr: &GraphRef<'_>,
    components: Vec<Vec<String>>,
    n: usize,
    runtime_policy: &fnx_runtime::RuntimePolicy,
    get_node_index: impl Fn(&str) -> Option<usize>,
    successors: impl Fn(usize) -> Option<&'a [usize]>,
) -> PyResult<PyObject> {
    let mut py_dg = PyDiGraph::new_empty_with_policy(py, runtime_policy.clone())?;
    let mapping = PyDict::new(py);
    let mut scc_of = vec![usize::MAX; n];

    for (idx, component) in components.iter().enumerate() {
        let label = idx.to_string();
        let py_nodes: Vec<PyObject> = component
            .iter()
            .map(|node| gr.py_node_key(py, node))
            .collect();
        let members = PySet::new(py, py_nodes)?;
        let attrs = PyDict::new(py);
        attrs.set_item("members", members)?;
        py_dg
            .node_key_map
            .insert(label.clone(), idx.into_pyobject(py)?.into_any().unbind());
        py_dg.node_py_attrs.insert(label, attrs.unbind());

        for node in component {
            if let Some(ni) = get_node_index(node) {
                scc_of[ni] = idx;
            }
            mapping.set_item(gr.py_node_key(py, node), idx)?;
        }
    }

    for idx in 0..components.len() {
        py_dg.inner.add_node(idx.to_string());
    }

    let mut seen = HashSet::new();
    let mut cond_edges = Vec::new();
    for u_idx in 0..n {
        let cu = scc_of[u_idx];
        let Some(succs) = successors(u_idx) else {
            continue;
        };
        for &v_idx in succs {
            let cv = scc_of[v_idx];
            if cu == cv || !seen.insert((cu, cv)) {
                continue;
            }
            let left = cu.to_string();
            let right = cv.to_string();
            py_dg
                .edge_py_attrs
                .insert((left.clone(), right.clone()), PyDict::new(py).unbind());
            cond_edges.push((left, right));
        }
    }
    let _ = py_dg.inner.extend_edges_unrecorded(cond_edges);
    py_dg.graph_attrs.bind(py).set_item("mapping", mapping)?;

    Ok(py_dg.into_pyobject(py)?.into_any().unbind())
}

