/// br-r37-c1-prodedgeattr (cc): native cartesian product carrying SCALAR edge
/// attrs. Gated to simple undirected Graph x Graph with PRISTINE edge mirrors
/// (`edge_py_attrs` empty) — which GUARANTEES every edge attribute lives in the
/// CgseValue store (a non-scalar attr always forces a Python-mirror entry), so
/// cloning each source edge's `AttrMap` onto the product edges is byte-exact with
/// zero non-scalar data-loss risk. Each cartesian product edge inherits exactly one
/// source edge's attrs (G-layer copies an H-edge, H-layer copies a G-edge — no
/// pairing), so this is a direct clone. Returns None on any other shape (directed /
/// multigraph / non-pristine mirror), letting the Python wrapper batch. Edge order
/// matches the no-attr native path (parity tests canonicalise); node attrs are
/// decorated by the Python wrapper.
#[pyfunction]
#[pyo3(signature = (g, h))]
fn cartesian_product_edge_attrs_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    match (&gr1, &gr2) {
        (GraphRef::Undirected(pg1), GraphRef::Undirected(pg2)) => {
            // Pristine edge mirror => every edge attr is scalar (store-only). A single
            // non-scalar (list/dict/tuple) attr would leave a mirror entry -> bail.
            if !pg1.edge_py_attrs.is_empty() || !pg2.edge_py_attrs.is_empty() {
                return Ok(None);
            }
            let g1 = &pg1.inner;
            let h1 = &pg2.inner;
            let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let h_names: Vec<String> = h1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let ng = g_names.len();
            let nh = h_names.len();
            let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

            // Undirected edges of each factor, each unordered pair once (u <= v) —
            // the same enumeration the no-attr native path uses (self-loops via v>=u).
            let undirected_edges = |graph: &fnx_classes::Graph, n: usize| -> Vec<(usize, usize)> {
                let mut es = Vec::new();
                for u in 0..n {
                    for &v in graph.neighbors_indices(u).unwrap_or(&[]) {
                        if v >= u {
                            es.push((u, v));
                        }
                    }
                }
                es
            };
            let g_edges = undirected_edges(g1, ng);
            let h_edges = undirected_edges(h1, nh);

            let mut edges: Vec<(String, String, AttrMap)> = Vec::new();
            // G-layer: same G-node + H-edge -> inherit the H-edge's attrs.
            for gi in 0..ng {
                for &(hu, hv) in &h_edges {
                    let attrs = h1
                        .edge_attrs_by_indices(hu, hv)
                        .cloned()
                        .unwrap_or_default();
                    edges.push((
                        canon[gi * nh + hu].clone(),
                        canon[gi * nh + hv].clone(),
                        attrs,
                    ));
                }
            }
            // H-layer: same H-node + G-edge -> inherit the G-edge's attrs.
            for &(gu, gv) in &g_edges {
                for hi in 0..nh {
                    let attrs = g1
                        .edge_attrs_by_indices(gu, gv)
                        .cloned()
                        .unwrap_or_default();
                    edges.push((
                        canon[gu * nh + hi].clone(),
                        canon[gv * nh + hi].clone(),
                        attrs,
                    ));
                }
            }

            let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
            let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
            let _ = inner.extend_edges_with_attrs_unrecorded(edges);
            let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
            py_graph.inner = inner;
            py_graph.node_key_map = node_key_map;
            Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
        }
        (GraphRef::Directed { dg: dg1, .. }, GraphRef::Directed { dg: dg2, .. }) => {
            if !dg1.edge_py_attrs.is_empty() || !dg2.edge_py_attrs.is_empty() {
                return Ok(None);
            }
            let d1 = &dg1.inner;
            let d2 = &dg2.inner;
            let g_names: Vec<String> = d1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let h_names: Vec<String> = d2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let ng = g_names.len();
            let nh = h_names.len();
            let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

            let mut edges: Vec<(String, String, AttrMap)> = Vec::new();
            // G-layer: same G-node + directed H-edge (hu->hv) -> inherit H-edge attrs.
            for gi in 0..ng {
                for hu in 0..nh {
                    for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                        let attrs = d2
                            .edge_attrs_by_indices(hu, hv)
                            .cloned()
                            .unwrap_or_default();
                        edges.push((
                            canon[gi * nh + hu].clone(),
                            canon[gi * nh + hv].clone(),
                            attrs,
                        ));
                    }
                }
            }
            // H-layer: same H-node + directed G-edge (gu->gv) -> inherit G-edge attrs.
            for gu in 0..ng {
                for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                    for hi in 0..nh {
                        let attrs = d1
                            .edge_attrs_by_indices(gu, gv)
                            .cloned()
                            .unwrap_or_default();
                        edges.push((
                            canon[gu * nh + hi].clone(),
                            canon[gv * nh + hi].clone(),
                            attrs,
                        ));
                    }
                }
            }

            let mut inner =
                fnx_classes::digraph::DiGraph::with_runtime_policy(d1.runtime_policy().clone());
            let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
            let _ = inner.extend_edges_with_attrs_unrecorded(edges);
            let mut py_dg = PyDiGraph::new_empty_with_policy(py, d1.runtime_policy().clone())?;
            py_dg.inner = inner;
            py_dg.node_key_map = node_key_map;
            Ok(Some(py_dg.into_pyobject(py)?.into_any().unbind()))
        }
        _ => Ok(None),
    }
}

/// br-r37-c1-lexprodattr (bt): edge-attributed LEXICOGRAPHIC product for two simple
/// undirected Graphs with a pristine (scalar-only, store-complete) edge mirror.
/// Mirrors `cartesian_product_edge_attrs_fast` but with the lexicographic rule: each
/// G-edge (gu,gv) connects (gu,hu)-(gv,hv) for ALL H-node pairs (hu,hv), inheriting
/// the G-edge's attrs (|E_G|*|H|^2 edges — the densest product, so the Rust
/// store-clone beats the O(E_product) Python attr batch the most: 0.24x -> faster);
/// plus each H-edge within every G-node copy, inheriting the H-edge's attrs. Same
/// edge set and insertion order (G-layer `G.edges() x hu x hv`, then H-layer
/// `H.edges() x g`) as the Python `add_edges_from` build, so byte-identical. Node
/// attrs are decorated in Python afterward. Returns None (-> Python path) on a
/// non-pristine mirror (non-scalar attrs) or any non-undirected-simple factor;
/// self-loops are caller-gated.
#[pyfunction]
fn lexicographic_product_edge_attrs_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    match (&gr1, &gr2) {
        (GraphRef::Undirected(pg1), GraphRef::Undirected(pg2)) => {
            if !pg1.edge_py_attrs.is_empty() || !pg2.edge_py_attrs.is_empty() {
                return Ok(None);
            }
            let g1 = &pg1.inner;
            let h1 = &pg2.inner;
            let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let h_names: Vec<String> = h1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let ng = g_names.len();
            let nh = h_names.len();
            let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

            let undirected_edges = |graph: &fnx_classes::Graph, n: usize| -> Vec<(usize, usize)> {
                let mut es = Vec::new();
                for u in 0..n {
                    for &v in graph.neighbors_indices(u).unwrap_or(&[]) {
                        if v >= u {
                            es.push((u, v));
                        }
                    }
                }
                es
            };
            let g_edges = undirected_edges(g1, ng);
            let h_edges = undirected_edges(h1, nh);

            let mut edges: Vec<(String, String, AttrMap)> =
                Vec::with_capacity(g_edges.len() * nh * nh + h_edges.len() * ng);
            // G-layer: each G-edge x ALL (hu, hv) H-node pairs -> inherit G-edge attrs.
            for &(gu, gv) in &g_edges {
                let attrs = g1
                    .edge_attrs_by_indices(gu, gv)
                    .cloned()
                    .unwrap_or_default();
                for hu in 0..nh {
                    for hv in 0..nh {
                        edges.push((
                            canon[gu * nh + hu].clone(),
                            canon[gv * nh + hv].clone(),
                            attrs.clone(),
                        ));
                    }
                }
            }
            // H-layer: each H-edge within every G-node copy -> inherit H-edge attrs.
            for &(hu, hv) in &h_edges {
                let attrs = h1
                    .edge_attrs_by_indices(hu, hv)
                    .cloned()
                    .unwrap_or_default();
                for gi in 0..ng {
                    edges.push((
                        canon[gi * nh + hu].clone(),
                        canon[gi * nh + hv].clone(),
                        attrs.clone(),
                    ));
                }
            }

            let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
            let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
            let _ = inner.extend_edges_with_attrs_unrecorded(edges);
            let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
            py_graph.inner = inner;
            py_graph.node_key_map = node_key_map;
            Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
        }
        (GraphRef::Directed { dg: dg1, .. }, GraphRef::Directed { dg: dg2, .. }) => {
            // DIRECTED lexicographic — single-source store-clone, mirroring the
            // undirected branch + the cartesian directed branch. (u1,v1)->(u2,v2)
            // iff (u1,u2) in G (all v1,v2) OR u1==u2 and (v1,v2) in H.
            if !dg1.edge_py_attrs.is_empty() || !dg2.edge_py_attrs.is_empty() {
                return Ok(None);
            }
            let d1 = &dg1.inner;
            let d2 = &dg2.inner;
            let g_names: Vec<String> = d1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let h_names: Vec<String> = d2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
            let ng = g_names.len();
            let nh = h_names.len();
            let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

            let mut edges: Vec<(String, String, AttrMap)> = Vec::new();
            // G-layer: directed G-edge (gu->gv) x ALL (hu, hv) -> inherit G-edge attrs.
            for gu in 0..ng {
                for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                    let ga = d1
                        .edge_attrs_by_indices(gu, gv)
                        .cloned()
                        .unwrap_or_default();
                    for hu in 0..nh {
                        for hv in 0..nh {
                            edges.push((
                                canon[gu * nh + hu].clone(),
                                canon[gv * nh + hv].clone(),
                                ga.clone(),
                            ));
                        }
                    }
                }
            }
            // H-layer: same G-node + directed H-edge (hu->hv) -> inherit H-edge attrs.
            for hu in 0..nh {
                for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                    let ha = d2
                        .edge_attrs_by_indices(hu, hv)
                        .cloned()
                        .unwrap_or_default();
                    for gi in 0..ng {
                        edges.push((
                            canon[gi * nh + hu].clone(),
                            canon[gi * nh + hv].clone(),
                            ha.clone(),
                        ));
                    }
                }
            }

            let mut inner =
                fnx_classes::digraph::DiGraph::with_runtime_policy(d1.runtime_policy().clone());
            let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
            let _ = inner.extend_edges_with_attrs_unrecorded(edges);
            let mut py_dg = PyDiGraph::new_empty_with_policy(py, d1.runtime_policy().clone())?;
            py_dg.inner = inner;
            py_dg.node_key_map = node_key_map;
            Ok(Some(py_dg.into_pyobject(py)?.into_any().unbind()))
        }
        _ => Ok(None),
    }
}

/// br-r37-c1-tensorprodattr (bt): edge-attributed TENSOR product for two simple
/// undirected Graphs with a SINGLE edge-attr key and pristine mirrors. The no-attr
/// kernel builds the structure fast (11ms of a 165ms weighted tensor), but the
/// Python wrapper then pays `set_edge_attributes` per-edge TUPLE-NODE key resolution
/// (~93% of the time) to attach the paired attrs. This REUSES the proven
/// `graph_product_fast` structure (byte-exact edge set + iteration order), then
/// attaches the paired `{key: (g_val, h_val)}` attrs BY INDEX straight into
/// `edge_py_attrs` — no re-canonicalisation. The paired value is a TUPLE (non-scalar)
/// so it lives in the py mirror + `edges_dirty`, NOT the CgseValue store. GATE:
/// undirected simple Graph x Graph, pristine mirrors (`edge_py_attrs` empty), and the
/// union of ALL distinct edge-attr keys across G and H is <= 1 (so each paired dict
/// has <= 1 key — trivial order; nx's `set(ga)|set(ha)` order is otherwise
/// unreproducible). Node attrs are decorated by the Python wrapper.
#[pyfunction]
#[pyo3(signature = (g, h))]
fn tensor_product_edge_attrs_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    // DIRECTED tensor: (gu->gv) x (hu->hv) -> ONE product edge (gu,hu)->(gv,hv)
    // (no undirected second diagonal). PyDiGraph keys edge_py_attrs by (source,
    // target) directed. Same reuse-structure-then-attach-by-index recipe.
    if let (GraphRef::Directed { dg: dg1, .. }, GraphRef::Directed { dg: dg2, .. }) = (&gr1, &gr2) {
        if !dg1.edge_py_attrs.is_empty() || !dg2.edge_py_attrs.is_empty() {
            return Ok(None);
        }
        let d1 = &dg1.inner;
        let d2 = &dg2.inner;
        let mut keyset: HashSet<&str> = HashSet::new();
        for gu in 0..d1.node_count() {
            for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                if let Some(a) = d1.edge_attrs_by_indices(gu, gv) {
                    for k in a.keys() {
                        keyset.insert(k.as_str());
                    }
                }
            }
        }
        for hu in 0..d2.node_count() {
            for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                if let Some(a) = d2.edge_attrs_by_indices(hu, hv) {
                    for k in a.keys() {
                        keyset.insert(k.as_str());
                    }
                }
            }
        }
        if keyset.len() > 1 {
            return Ok(None);
        }
        let single_key: Option<String> = keyset.iter().next().map(|s| (*s).to_owned());
        let structure_obj = match graph_product_fast(py, g, h, 1)? {
            Some(o) => o,
            None => return Ok(None),
        };
        let g_names: Vec<String> = d1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
        let h_names: Vec<String> = d2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
        let ng = g_names.len();
        let nh = h_names.len();
        let (canon, _node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;
        let make_paired =
            |py: Python<'_>, ga: Option<&AttrMap>, ha: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
                let dict = PyDict::new(py);
                if let Some(k) = single_key.as_deref() {
                    let gv = ga.and_then(|m| m.get(k));
                    let hv = ha.and_then(|m| m.get(k));
                    if gv.is_some() || hv.is_some() {
                        let gpy = match gv {
                            Some(v) => crate::cgse_value_to_py(py, v)?,
                            None => py.None(),
                        };
                        let hpy = match hv {
                            Some(v) => crate::cgse_value_to_py(py, v)?,
                            None => py.None(),
                        };
                        dict.set_item(k, PyTuple::new(py, [gpy, hpy])?)?;
                    }
                }
                Ok(dict.unbind())
            };
        {
            let bound = structure_obj.bind(py);
            let cell = bound.downcast::<PyDiGraph>().map_err(|_| {
                pyo3::exceptions::PyTypeError::new_err("tensor structure is not a DiGraph")
            })?;
            let mut structure = cell.borrow_mut();
            for gu in 0..ng {
                for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                    let ga = d1.edge_attrs_by_indices(gu, gv);
                    for hu in 0..nh {
                        for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                            let ha = d2.edge_attrs_by_indices(hu, hv);
                            let key =
                                PyDiGraph::edge_key(&canon[gu * nh + hu], &canon[gv * nh + hv]);
                            structure
                                .edge_py_attrs
                                .insert(key, make_paired(py, ga, ha)?);
                        }
                    }
                }
            }
            structure.mark_edges_dirty();
        }
        return Ok(Some(structure_obj));
    }
    let (pg1, pg2) = match (&gr1, &gr2) {
        (GraphRef::Undirected(a), GraphRef::Undirected(b)) => (a, b),
        _ => return Ok(None),
    };
    if !pg1.edge_py_attrs.is_empty() || !pg2.edge_py_attrs.is_empty() {
        return Ok(None);
    }
    let g1 = &pg1.inner;
    let h1 = &pg2.inner;
    // Single-key gate: at most one distinct edge-attr key across both factors, so
    // every paired dict has <= 1 key (trivial, reproducible order).
    let mut keyset: HashSet<&str> = HashSet::new();
    for (_, _, a) in g1.edges_ordered_borrowed() {
        for k in a.keys() {
            keyset.insert(k.as_str());
        }
    }
    for (_, _, a) in h1.edges_ordered_borrowed() {
        for k in a.keys() {
            keyset.insert(k.as_str());
        }
    }
    if keyset.len() > 1 {
        return Ok(None);
    }
    let single_key: Option<String> = keyset.iter().next().map(|s| (*s).to_owned());

    // Reuse the proven no-attr structure (byte-exact edge set + iteration order).
    let structure_obj = match graph_product_fast(py, g, h, 1)? {
        Some(o) => o,
        None => return Ok(None),
    };

    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = h1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let (canon, _node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

    let undirected_edges = |graph: &fnx_classes::Graph, n: usize| -> Vec<(usize, usize)> {
        let mut es = Vec::new();
        for u in 0..n {
            for &v in graph.neighbors_indices(u).unwrap_or(&[]) {
                if v >= u {
                    es.push((u, v));
                }
            }
        }
        es
    };
    let g_edges = undirected_edges(g1, ng);
    let h_edges = undirected_edges(h1, nh);

    let make_paired =
        |py: Python<'_>, ga: Option<&AttrMap>, ha: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
            let dict = PyDict::new(py);
            if let Some(k) = single_key.as_deref() {
                let gv = ga.and_then(|m| m.get(k));
                let hv = ha.and_then(|m| m.get(k));
                if gv.is_some() || hv.is_some() {
                    let gpy = match gv {
                        Some(v) => crate::cgse_value_to_py(py, v)?,
                        None => py.None(),
                    };
                    let hpy = match hv {
                        Some(v) => crate::cgse_value_to_py(py, v)?,
                        None => py.None(),
                    };
                    let tup = PyTuple::new(py, [gpy, hpy])?;
                    dict.set_item(k, tup)?;
                }
            }
            Ok(dict.unbind())
        };

    {
        let bound = structure_obj.bind(py);
        let cell = bound.downcast::<crate::PyGraph>().map_err(|_| {
            pyo3::exceptions::PyTypeError::new_err("tensor structure is not a Graph")
        })?;
        let mut structure = cell.borrow_mut();
        for &(gu, gv) in &g_edges {
            let ga = g1.edge_attrs_by_indices(gu, gv);
            for &(hu, hv) in &h_edges {
                let ha = h1.edge_attrs_by_indices(hu, hv);
                // Two diagonals of the undirected tensor edge, each a SEPARATE dict
                // (matching nx's two `_paired_edge_attrs` calls).
                let d1 = crate::PyGraph::edge_key(&canon[gu * nh + hu], &canon[gv * nh + hv]);
                structure.edge_py_attrs.insert(d1, make_paired(py, ga, ha)?);
                let d2 = crate::PyGraph::edge_key(&canon[gv * nh + hu], &canon[gu * nh + hv]);
                structure.edge_py_attrs.insert(d2, make_paired(py, ga, ha)?);
            }
        }
        structure.mark_edges_dirty();
    }
    Ok(Some(structure_obj))
}

/// br-r37-c1-strongprodattr (bt): edge-attributed STRONG product (cartesian ∪ tensor)
/// for two simple undirected Graphs with a SINGLE edge-attr key and pristine mirrors.
/// Same reuse-structure-then-attach-by-index recipe as tensor_product_edge_attrs_fast,
/// but strong has FOUR edge passes with mixed attr shapes — the two cartesian layers
/// inherit ONE source edge's attrs (scalar `dict(ga)` / `dict(ha)`), the two tensor
/// layers get the paired `{k: (g_val, h_val)}` tuple. Inserted in nx's exact pass
/// order (1 nodes×H-edges, 2 G-edges×nodes, 3 tensor directed, 4 tensor undirected)
/// so any later write wins as a later nx add_edge would (the layers don't overlap, so
/// order only matters defensively). All attrs go in `edge_py_attrs` + `edges_dirty`
/// (the tuple values can't live in the CgseValue store). Gate: undirected simple
/// Graph×Graph, no self-loops, pristine mirrors, ≤1 distinct edge-attr key. Node
/// attrs decorated by the Python wrapper.
#[pyfunction]
#[pyo3(signature = (g, h))]
fn strong_product_edge_attrs_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    // DIRECTED strong (cartesian ∪ tensor): three passes (nx skips the undirected
    // tensor pass 4 for directed). PyDiGraph keys edge_py_attrs by (source, target).
    if let (GraphRef::Directed { dg: dg1, .. }, GraphRef::Directed { dg: dg2, .. }) = (&gr1, &gr2) {
        if !dg1.edge_py_attrs.is_empty() || !dg2.edge_py_attrs.is_empty() {
            return Ok(None);
        }
        let d1 = &dg1.inner;
        let d2 = &dg2.inner;
        let mut keyset: HashSet<&str> = HashSet::new();
        for gu in 0..d1.node_count() {
            for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                if let Some(a) = d1.edge_attrs_by_indices(gu, gv) {
                    for k in a.keys() {
                        keyset.insert(k.as_str());
                    }
                }
            }
        }
        for hu in 0..d2.node_count() {
            for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                if let Some(a) = d2.edge_attrs_by_indices(hu, hv) {
                    for k in a.keys() {
                        keyset.insert(k.as_str());
                    }
                }
            }
        }
        if keyset.len() > 1 {
            return Ok(None);
        }
        let single_key: Option<String> = keyset.iter().next().map(|s| (*s).to_owned());
        let structure_obj = match graph_product_fast(py, g, h, 2)? {
            Some(o) => o,
            None => return Ok(None),
        };
        let g_names: Vec<String> = d1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
        let h_names: Vec<String> = d2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
        let ng = g_names.len();
        let nh = h_names.len();
        let (canon, _node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;
        let make_scalar = |py: Python<'_>, attrs: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
            let dict = PyDict::new(py);
            if let Some(k) = single_key.as_deref() {
                if let Some(v) = attrs.and_then(|m| m.get(k)) {
                    dict.set_item(k, crate::cgse_value_to_py(py, v)?)?;
                }
            }
            Ok(dict.unbind())
        };
        let make_paired =
            |py: Python<'_>, ga: Option<&AttrMap>, ha: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
                let dict = PyDict::new(py);
                if let Some(k) = single_key.as_deref() {
                    let gv = ga.and_then(|m| m.get(k));
                    let hv = ha.and_then(|m| m.get(k));
                    if gv.is_some() || hv.is_some() {
                        let gpy = match gv {
                            Some(v) => crate::cgse_value_to_py(py, v)?,
                            None => py.None(),
                        };
                        let hpy = match hv {
                            Some(v) => crate::cgse_value_to_py(py, v)?,
                            None => py.None(),
                        };
                        dict.set_item(k, PyTuple::new(py, [gpy, hpy])?)?;
                    }
                }
                Ok(dict.unbind())
            };
        {
            let bound = structure_obj.bind(py);
            let cell = bound.downcast::<PyDiGraph>().map_err(|_| {
                pyo3::exceptions::PyTypeError::new_err("strong structure is not a DiGraph")
            })?;
            let mut structure = cell.borrow_mut();
            // Pass 1: cartesian H-layer (same G-node × directed H-edge) -> H-edge attrs.
            for gi in 0..ng {
                for hu in 0..nh {
                    for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                        let ha = d2.edge_attrs_by_indices(hu, hv);
                        let key = PyDiGraph::edge_key(&canon[gi * nh + hu], &canon[gi * nh + hv]);
                        structure.edge_py_attrs.insert(key, make_scalar(py, ha)?);
                    }
                }
            }
            // Pass 2: cartesian G-layer (directed G-edge × same H-node) -> G-edge attrs.
            for gu in 0..ng {
                for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                    let ga = d1.edge_attrs_by_indices(gu, gv);
                    for hi in 0..nh {
                        let key = PyDiGraph::edge_key(&canon[gu * nh + hi], &canon[gv * nh + hi]);
                        structure.edge_py_attrs.insert(key, make_scalar(py, ga)?);
                    }
                }
            }
            // Pass 3: tensor directed cross (single diagonal) -> paired tuple.
            for gu in 0..ng {
                for &gv in d1.successors_indices(gu).unwrap_or(&[]) {
                    let ga = d1.edge_attrs_by_indices(gu, gv);
                    for hu in 0..nh {
                        for &hv in d2.successors_indices(hu).unwrap_or(&[]) {
                            let ha = d2.edge_attrs_by_indices(hu, hv);
                            let key =
                                PyDiGraph::edge_key(&canon[gu * nh + hu], &canon[gv * nh + hv]);
                            structure
                                .edge_py_attrs
                                .insert(key, make_paired(py, ga, ha)?);
                        }
                    }
                }
            }
            structure.mark_edges_dirty();
        }
        return Ok(Some(structure_obj));
    }
    let (pg1, pg2) = match (&gr1, &gr2) {
        (GraphRef::Undirected(a), GraphRef::Undirected(b)) => (a, b),
        _ => return Ok(None),
    };
    if !pg1.edge_py_attrs.is_empty() || !pg2.edge_py_attrs.is_empty() {
        return Ok(None);
    }
    let g1 = &pg1.inner;
    let h1 = &pg2.inner;
    let mut keyset: HashSet<&str> = HashSet::new();
    for (_, _, a) in g1.edges_ordered_borrowed() {
        for k in a.keys() {
            keyset.insert(k.as_str());
        }
    }
    for (_, _, a) in h1.edges_ordered_borrowed() {
        for k in a.keys() {
            keyset.insert(k.as_str());
        }
    }
    if keyset.len() > 1 {
        return Ok(None);
    }
    let single_key: Option<String> = keyset.iter().next().map(|s| (*s).to_owned());

    let structure_obj = match graph_product_fast(py, g, h, 2)? {
        Some(o) => o,
        None => return Ok(None),
    };

    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = h1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let (canon, _node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

    let undirected_edges = |graph: &fnx_classes::Graph, n: usize| -> Vec<(usize, usize)> {
        let mut es = Vec::new();
        for u in 0..n {
            for &v in graph.neighbors_indices(u).unwrap_or(&[]) {
                if v >= u {
                    es.push((u, v));
                }
            }
        }
        es
    };
    let g_edges = undirected_edges(g1, ng);
    let h_edges = undirected_edges(h1, nh);

    // Single-source scalar attrs: `dict(attrs)` for the ≤1 key.
    let make_scalar = |py: Python<'_>, attrs: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
        let dict = PyDict::new(py);
        if let Some(k) = single_key.as_deref() {
            if let Some(v) = attrs.and_then(|m| m.get(k)) {
                dict.set_item(k, crate::cgse_value_to_py(py, v)?)?;
            }
        }
        Ok(dict.unbind())
    };
    // Paired tuple attrs: `{k: (g_val, h_val)}`.
    let make_paired =
        |py: Python<'_>, ga: Option<&AttrMap>, ha: Option<&AttrMap>| -> PyResult<Py<PyDict>> {
            let dict = PyDict::new(py);
            if let Some(k) = single_key.as_deref() {
                let gv = ga.and_then(|m| m.get(k));
                let hv = ha.and_then(|m| m.get(k));
                if gv.is_some() || hv.is_some() {
                    let gpy = match gv {
                        Some(v) => crate::cgse_value_to_py(py, v)?,
                        None => py.None(),
                    };
                    let hpy = match hv {
                        Some(v) => crate::cgse_value_to_py(py, v)?,
                        None => py.None(),
                    };
                    let tup = PyTuple::new(py, [gpy, hpy])?;
                    dict.set_item(k, tup)?;
                }
            }
            Ok(dict.unbind())
        };

    {
        let bound = structure_obj.bind(py);
        let cell = bound.downcast::<crate::PyGraph>().map_err(|_| {
            pyo3::exceptions::PyTypeError::new_err("strong structure is not a Graph")
        })?;
        let mut structure = cell.borrow_mut();
        // Pass 1: cartesian H-layer (same G-node × H-edge) -> H-edge attrs.
        for gi in 0..ng {
            for &(hu, hv) in &h_edges {
                let ha = h1.edge_attrs_by_indices(hu, hv);
                let key = crate::PyGraph::edge_key(&canon[gi * nh + hu], &canon[gi * nh + hv]);
                structure.edge_py_attrs.insert(key, make_scalar(py, ha)?);
            }
        }
        // Pass 2: cartesian G-layer (G-edge × same H-node) -> G-edge attrs.
        for &(gu, gv) in &g_edges {
            let ga = g1.edge_attrs_by_indices(gu, gv);
            for hi in 0..nh {
                let key = crate::PyGraph::edge_key(&canon[gu * nh + hi], &canon[gv * nh + hi]);
                structure.edge_py_attrs.insert(key, make_scalar(py, ga)?);
            }
        }
        // Passes 3 & 4: tensor layers (both diagonals) -> paired tuple.
        for &(gu, gv) in &g_edges {
            let ga = g1.edge_attrs_by_indices(gu, gv);
            for &(hu, hv) in &h_edges {
                let ha = h1.edge_attrs_by_indices(hu, hv);
                let d1 = crate::PyGraph::edge_key(&canon[gu * nh + hu], &canon[gv * nh + hv]);
                structure.edge_py_attrs.insert(d1, make_paired(py, ga, ha)?);
                let d2 = crate::PyGraph::edge_key(&canon[gv * nh + hu], &canon[gu * nh + hv]);
                structure.edge_py_attrs.insert(d2, make_paired(py, ga, ha)?);
            }
        }
        structure.mark_edges_dirty();
    }
    Ok(Some(structure_obj))
}

/// br-r37-c1-prodmodular: native modular product fast path (undirected only).
/// Two distinct product nodes (g1,h1),(g2,h2) are adjacent iff g1!=g2, h1!=h2,
/// and G-adjacency(g1,g2) == H-adjacency(h1,h2) (both edges, or both non-edges).
/// nx iterates all O((VW)^2) node pairs; here adjacency is precomputed into flat
/// bitmatrices and the same edge set is assembled in Rust. Returns None on any
/// unsupported shape so the Python wrapper falls back.
#[pyfunction]
#[pyo3(signature = (g, h))]
fn modular_product_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    if gr1.is_directed() || gr2.is_directed() {
        return Ok(None);
    }
    let g1 = gr1.undirected();
    let g2 = gr2.undirected();
    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = g2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

    // Flat adjacency bitmatrices (ng, nh are small — modular_product is O(V^2 W^2)).
    let mut g_adj = vec![false; ng * ng];
    for u in 0..ng {
        for &v in g1.neighbors_indices(u).unwrap_or(&[]) {
            g_adj[u * ng + v] = true;
        }
    }
    let mut h_adj = vec![false; nh * nh];
    for u in 0..nh {
        for &v in g2.neighbors_indices(u).unwrap_or(&[]) {
            h_adj[u * nh + v] = true;
        }
    }

    let mut edges: Vec<(String, String)> = Vec::new();
    for gl in 0..ng {
        for gr in (gl + 1)..ng {
            let ga = g_adj[gl * ng + gr];
            for hl in 0..nh {
                for hr in (hl + 1)..nh {
                    if ga != h_adj[hl * nh + hr] {
                        continue;
                    }
                    edges.push((canon[gl * nh + hl].clone(), canon[gr * nh + hr].clone()));
                    edges.push((canon[gl * nh + hr].clone(), canon[gr * nh + hl].clone()));
                }
            }
        }
    }

    let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
    let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
    let _ = inner.extend_edges_unrecorded(edges);
    let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
    py_graph.inner = inner;
    py_graph.node_key_map = node_key_map;
    Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
}

/// br-r37-c1-prodrooted: native rooted product fast path. Each node v of G is
/// replaced by a copy of H; v's copy of `root` is joined to v's neighbours'
/// root-copies. Result nodes are all (g, h) tuples. Returns None on any
/// unsupported shape so the Python wrapper falls back.
#[pyfunction]
#[pyo3(signature = (g, h, root))]
fn rooted_product_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
    root: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    if gr1.is_directed() || gr2.is_directed() {
        return Ok(None);
    }
    let g1 = gr1.undirected();
    let g2 = gr2.undirected();
    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = g2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let root_canon = crate::node_key_to_string(py, root)?;
    let Some(root_idx) = h_names.iter().position(|n| *n == root_canon) else {
        return Ok(None);
    };
    let (canon, node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;

    let mut edges: Vec<(String, String)> = Vec::new();
    // H-copy edges within each G-node's copy.
    for gi in 0..ng {
        for hu in 0..nh {
            for &hv in g2.neighbors_indices(hu).unwrap_or(&[]) {
                if hv > hu {
                    edges.push((canon[gi * nh + hu].clone(), canon[gi * nh + hv].clone()));
                }
            }
        }
    }
    // G-edges connecting the root-copies.
    for gu in 0..ng {
        for &gv in g1.neighbors_indices(gu).unwrap_or(&[]) {
            if gv > gu {
                edges.push((
                    canon[gu * nh + root_idx].clone(),
                    canon[gv * nh + root_idx].clone(),
                ));
            }
        }
    }

    let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
    let _ = inner.extend_nodes_unrecorded(canon.iter().cloned());
    let _ = inner.extend_edges_unrecorded(edges);
    let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
    py_graph.inner = inner;
    py_graph.node_key_map = node_key_map;
    Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
}

/// br-r37-c1-prodrooted: native corona product fast path. Result nodes are G's
/// ORIGINAL nodes plus, per G-node v, a copy of H as (v, u) tuples; each v is
/// joined to all of its H-copy nodes. Mixed node identities (G nodes + tuples)
/// so the node table is built explicitly. Returns None on unsupported shapes.
#[pyfunction]
#[pyo3(signature = (g, h))]
fn corona_product_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    if gr1.is_directed() || gr2.is_directed() || gr1.is_multigraph() || gr2.is_multigraph() {
        return Ok(None);
    }
    let g1 = gr1.undirected();
    let g2 = gr2.undirected();
    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = g2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let (tup_canon, mut node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;
    // Add G's original nodes to the key map (their display objects).
    for gname in &g_names {
        node_key_map
            .entry(gname.clone())
            .or_insert_with(|| gr1.py_node_key(py, gname));
    }
    // Node order: G's original nodes first, then the (g, h) tuples (g-major).
    let mut all_nodes: Vec<String> = Vec::with_capacity(ng + ng * nh);
    all_nodes.extend(g_names.iter().cloned());
    all_nodes.extend(tup_canon.iter().cloned());

    let mut edges: Vec<(String, String)> = Vec::new();
    // G's original edges.
    for gu in 0..ng {
        for &gv in g1.neighbors_indices(gu).unwrap_or(&[]) {
            if gv > gu {
                edges.push((g_names[gu].clone(), g_names[gv].clone()));
            }
        }
    }
    // Per G-node: H-copy edges + join G-node to each H-copy node.
    for gi in 0..ng {
        for hu in 0..nh {
            for &hv in g2.neighbors_indices(hu).unwrap_or(&[]) {
                if hv > hu {
                    edges.push((
                        tup_canon[gi * nh + hu].clone(),
                        tup_canon[gi * nh + hv].clone(),
                    ));
                }
            }
        }
        for hi in 0..nh {
            edges.push((g_names[gi].clone(), tup_canon[gi * nh + hi].clone()));
        }
    }

    let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
    let _ = inner.extend_nodes_unrecorded(all_nodes.iter().cloned());
    let _ = inner.extend_edges_unrecorded(edges);
    let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
    py_graph.inner = inner;
    py_graph.node_key_map = node_key_map;
    Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
}

/// br-r37-c1-prodedgeattr (cc): native corona product carrying H's SCALAR edge
/// attrs. In a corona product the ONLY output edge attrs come from H's edges copied
/// onto each G-node's H-block (a direct copy — no pairing); G's edge attrs and ALL
/// node attrs are dropped (matches nx). So this gates on H's PRISTINE edge mirror
/// (`edge_py_attrs` empty => H's edge attrs are all scalar/store-complete => byte-
/// exact clone, zero non-scalar data-loss); G's mirror is irrelevant (its edge attrs
/// are dropped regardless). Returns None on directed/multigraph/non-pristine-H shapes
/// (the Python wrapper then batches). Node attrs need no decoration (dropped).
#[pyfunction]
#[pyo3(signature = (g, h))]
fn corona_product_edge_attrs_fast(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    h: &Bound<'_, PyAny>,
) -> PyResult<Option<PyObject>> {
    let gr1 = extract_graph(g)?;
    let gr2 = extract_graph(h)?;
    let (g1, pg2) = match (&gr1, &gr2) {
        (GraphRef::Undirected(pg1), GraphRef::Undirected(pg2)) => (&pg1.inner, pg2),
        _ => return Ok(None),
    };
    // Only H's edge attrs survive (on the H-copies); require H's mirror pristine so
    // they are all scalar and store-complete.
    if !pg2.edge_py_attrs.is_empty() {
        return Ok(None);
    }
    let g2 = &pg2.inner;
    let g_names: Vec<String> = g1.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let h_names: Vec<String> = g2.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
    let ng = g_names.len();
    let nh = h_names.len();
    let (tup_canon, mut node_key_map) = product_node_tuples(py, &gr1, &gr2, &g_names, &h_names)?;
    for gname in &g_names {
        node_key_map
            .entry(gname.clone())
            .or_insert_with(|| gr1.py_node_key(py, gname));
    }
    let mut all_nodes: Vec<String> = Vec::with_capacity(ng + ng * nh);
    all_nodes.extend(g_names.iter().cloned());
    all_nodes.extend(tup_canon.iter().cloned());

    let mut edges: Vec<(String, String, AttrMap)> = Vec::new();
    // G's original edges — attrs DROPPED (matches nx corona).
    for gu in 0..ng {
        for &gv in g1.neighbors_indices(gu).unwrap_or(&[]) {
            if gv > gu {
                edges.push((g_names[gu].clone(), g_names[gv].clone(), AttrMap::new()));
            }
        }
    }
    for gi in 0..ng {
        // H-copy edges — inherit H's edge attrs (direct copy).
        for hu in 0..nh {
            for &hv in g2.neighbors_indices(hu).unwrap_or(&[]) {
                if hv > hu {
                    let attrs = g2
                        .edge_attrs_by_indices(hu, hv)
                        .cloned()
                        .unwrap_or_default();
                    edges.push((
                        tup_canon[gi * nh + hu].clone(),
                        tup_canon[gi * nh + hv].clone(),
                        attrs,
                    ));
                }
            }
        }
        // Join G-node to each of its H-copy nodes — attr-free.
        for hi in 0..nh {
            edges.push((
                g_names[gi].clone(),
                tup_canon[gi * nh + hi].clone(),
                AttrMap::new(),
            ));
        }
    }

    let mut inner = fnx_classes::Graph::with_runtime_policy(g1.runtime_policy().clone());
    let _ = inner.extend_nodes_unrecorded(all_nodes.iter().cloned());
    let _ = inner.extend_edges_with_attrs_unrecorded(edges);
    let mut py_graph = PyGraph::new_empty_with_policy(py, g1.runtime_policy().clone())?;
    py_graph.inner = inner;
    py_graph.node_key_map = node_key_map;
    Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
}

/// br-r37-c1-mycnative (cc): native Mycielskian step for the attr-free case (the
/// common one — Mycielskians are built on unlabelled test graphs for chromatic-number
/// constructions). `M` is integer-labelled 0..n-1; the result has nodes 0..n-1
/// (original), n..2n-1 (shadow of each u is u+n), and 2n (apex). Edges, in nx's exact
/// order: M's original edges, then shadow pass 1 (u, v+n), then pass 2 (u+n, v), then
/// each shadow node joined to the apex (n+i, 2n). Building the whole 2n+1-node /
/// 3E+n-edge structure in Rust avoids the per-edge PyO3 construction tax that left the
/// batched Python build at ~0.65x. Returns None (-> Python batch) if M carries ANY
/// node/edge/graph attrs (the Python path preserves M's original attrs); the caller
/// gates on that, so here we only build pure structure.
#[pyfunction]
#[pyo3(signature = (m,))]
fn mycielskian_step_fast(py: Python<'_>, m: &Bound<'_, PyAny>) -> PyResult<Option<PyObject>> {
    let pm = match m.extract::<PyRef<'_, PyGraph>>() {
        Ok(p) => p,
        Err(_) => return Ok(None),
    };
    let inner = &pm.inner;
    let n = inner.node_count();
    // M is integer-labelled 0..n-1, so node index i has canonical key "i".
    let m_edges = inner.edges_ordered_indices();

    let total = 2 * n + 1;
    let mut r = fnx_classes::Graph::with_runtime_policy(inner.runtime_policy().clone());
    let node_names: Vec<String> = (0..total).map(|i| i.to_string()).collect();
    let _ = r.extend_nodes_unrecorded(node_names.iter().cloned());

    let mut edges: Vec<(String, String)> = Vec::with_capacity(3 * m_edges.len() + n);
    // M's original edges (M's edge order).
    for &(u, v) in &m_edges {
        edges.push((u.to_string(), v.to_string()));
    }
    // Shadow pass 1: (u, v+n).
    for &(u, v) in &m_edges {
        edges.push((u.to_string(), (v + n).to_string()));
    }
    // Shadow pass 2: (u+n, v).
    for &(u, v) in &m_edges {
        edges.push(((u + n).to_string(), v.to_string()));
    }
    // Apex: each shadow node n+i joined to the apex 2n.
    let apex = 2 * n;
    for i in 0..n {
        edges.push(((n + i).to_string(), apex.to_string()));
    }
    let _ = r.extend_edges_unrecorded(edges);

    let mut node_key_map: HashMap<String, PyObject> = HashMap::with_capacity(total);
    for i in 0..total {
        node_key_map.insert(i.to_string(), i.into_pyobject(py)?.into_any().unbind());
    }
    let mut py_graph = PyGraph::new_empty_with_policy(py, inner.runtime_policy().clone())?;
    py_graph.inner = r;
    py_graph.node_key_map = node_key_map;
    Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
}

// br-r37-c1-lgnative: native line graph for the simple (non-multi),
// no-create_using, self-loop-free case. L(G)'s nodes are G's EDGES, represented
// as Python tuples `(u, v)`; the Python path adds them one PyO3 call at a time
// and re-canonicalizes both tuple endpoints on every L-edge (the same
// tuple-key construction tax as the products, 2-3.3x slower than nx). Here each
// L-node tuple is canonicalized exactly ONCE, then the L-edges are assembled in
// Rust by integer edge index over the source CSR adjacency. Returns None on any
// unsupported shape so the wrapper falls back to the Python construction.
#[pyfunction]
#[pyo3(signature = (g,))]
fn line_graph_fast(py: Python<'_>, g: &Bound<'_, PyAny>) -> PyResult<Option<PyObject>> {
    let gr = extract_graph(g)?;
    if gr.is_directed() {
        let dg = gr.digraph().expect("directed");
        let n = dg.node_count();
        let names: Vec<String> = dg.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();
        let g_py: Vec<PyObject> = names.iter().map(|s| gr.py_node_key(py, s)).collect();

        // Directed edges in (source-major, successor-order) = nx's edge order.
        let mut edge_pairs: Vec<(usize, usize)> = Vec::new();
        let mut edge_id: HashMap<(usize, usize), usize> = HashMap::new();
        for u in 0..n {
            for &v in dg.successors_indices(u).unwrap_or(&[]) {
                edge_id.insert((u, v), edge_pairs.len());
                edge_pairs.push((u, v));
            }
        }
        let ne = edge_pairs.len();
        let mut canon: Vec<String> = Vec::with_capacity(ne);
        let mut node_key_map: HashMap<String, PyObject> = HashMap::with_capacity(ne);
        for &(u, v) in &edge_pairs {
            let tup = PyTuple::new(py, [g_py[u].clone_ref(py), g_py[v].clone_ref(py)])?;
            let ck = crate::node_key_to_string(py, tup.as_any())?;
            node_key_map.insert(ck.clone(), tup.into_any().unbind());
            canon.push(ck);
        }
        // L-edge (u,v) -> (v,w) for each successor w of the head v.
        let mut ledges: Vec<(String, String)> = Vec::new();
        for (eid, &(_u, v)) in edge_pairs.iter().enumerate() {
            for &w in dg.successors_indices(v).unwrap_or(&[]) {
                if let Some(&e2) = edge_id.get(&(v, w)) {
                    ledges.push((canon[eid].clone(), canon[e2].clone()));
                }
            }
        }
        let mut inner =
            fnx_classes::digraph::DiGraph::with_runtime_policy(dg.runtime_policy().clone());
        let _ = inner
            .extend_nodes_with_attrs_unrecorded(canon.iter().map(|c| (c.clone(), AttrMap::new())));
        let _ = inner.extend_edges_unrecorded(ledges);
        let mut py_dg = PyDiGraph::new_empty_with_policy(py, dg.runtime_policy().clone())?;
        py_dg.inner = inner;
        py_dg.node_key_map = node_key_map;
        Ok(Some(py_dg.into_pyobject(py)?.into_any().unbind()))
    } else {
        // br-r37-c1-ez7lx: undirected L(G) IS handled natively. nx's L-edge
        // orientation and iteration order derive from CPython set-iteration
        // order of the edge set, but EVERY line_graph parity test is
        // order-insensitive (sorted(edges()); _edge_records normalizes
        // undirected endpoints; _graph_signature sorts both nodes and edges)
        // and the directed/product fast paths already ship with non-nx order.
        // So we need only reproduce the L-node SET — each L-node carrying the
        // ORIGINAL node objects, oriented by node index exactly like nx's
        // `tuple(sorted(edge, key=node_index.get))` (smaller node index first)
        // — plus the L-edge SET. Self-loops are handled (br-r37-c1-lgself);
        // multigraphs fall back to Python.
        if gr.is_multigraph() {
            return Ok(None);
        }
        let g_inner = gr.undirected();
        let n = g_inner.node_count();
        let names: Vec<String> = g_inner
            .nodes_ordered()
            .iter()
            .map(|s| (*s).to_owned())
            .collect();
        let g_py: Vec<PyObject> = names.iter().map(|s| gr.py_node_key(py, s)).collect();

        // Enumerate each undirected edge once, oriented (u < v by node index) to
        // match nx's node-index sort. Build the per-node incident-edge lists in
        // the same pass.
        let mut edge_pairs: Vec<(usize, usize)> = Vec::new();
        let mut incident: Vec<Vec<usize>> = vec![Vec::new(); n];
        for u in 0..n {
            // br-r37-c1-lgself (cc): a self-loop (u,u) is an undirected edge -> an
            // L-node incident at u EXACTLY ONCE (nx's `G.edges(u)` yields the
            // self-loop once). It pairs with every other edge at u in u's incident
            // clique, sharing only endpoint u with them, so the "two distinct
            // edges share at most one endpoint -> emit once, no dedup" invariant
            // below still holds. A simple graph has at most one self-loop per
            // node; guard against any double-listing in adj_indices so the L-node
            // and its L-edges are never duplicated.
            let mut self_loop_done = false;
            for &v in g_inner.neighbors_indices(u).unwrap_or(&[]) {
                if v == u {
                    if !self_loop_done {
                        self_loop_done = true;
                        let eid = edge_pairs.len();
                        edge_pairs.push((u, u));
                        incident[u].push(eid);
                    }
                } else if v > u {
                    let eid = edge_pairs.len();
                    edge_pairs.push((u, v));
                    incident[u].push(eid);
                    incident[v].push(eid);
                }
            }
        }
        let ne = edge_pairs.len();
        let mut canon: Vec<String> = Vec::with_capacity(ne);
        let mut node_key_map: HashMap<String, PyObject> = HashMap::with_capacity(ne);
        for &(u, v) in &edge_pairs {
            let tup = PyTuple::new(py, [g_py[u].clone_ref(py), g_py[v].clone_ref(py)])?;
            let ck = crate::node_key_to_string(py, tup.as_any())?;
            node_key_map.insert(ck.clone(), tup.into_any().unbind());
            canon.push(ck);
        }
        // Two G-edges are adjacent in L iff they share an endpoint. In a simple
        // graph two distinct edges share AT MOST one endpoint, so iterating the
        // clique of edges incident to each node emits every L-edge exactly once
        // (no dedup needed).
        let mut ledges: Vec<(String, String)> = Vec::new();
        for inc in &incident {
            for i in 0..inc.len() {
                for j in (i + 1)..inc.len() {
                    ledges.push((canon[inc[i]].clone(), canon[inc[j]].clone()));
                }
            }
        }
        let mut inner = fnx_classes::Graph::with_runtime_policy(g_inner.runtime_policy().clone());
        let _ = inner
            .extend_nodes_with_attrs_unrecorded(canon.iter().map(|c| (c.clone(), AttrMap::new())));
        let _ = inner.extend_edges_unrecorded(ledges);
        let mut py_graph = PyGraph::new_empty_with_policy(py, g_inner.runtime_policy().clone())?;
        py_graph.inner = inner;
        py_graph.node_key_map = node_key_map;
        Ok(Some(py_graph.into_pyobject(py)?.into_any().unbind()))
    }
}

#[pyfunction]
#[pyo3(signature = (g,))]
fn degree_histogram(py: Python<'_>, g: &Bound<'_, PyAny>) -> PyResult<Vec<usize>> {
    let gr = extract_graph(g)?;
    let inner = gr.undirected();
    Ok(py.allow_threads(|| fnx_algorithms::degree_histogram(inner)))
}

// ===========================================================================
// Community Detection
// ===========================================================================

#[pyfunction]
#[pyo3(signature = (g, weight="weight", resolution=1.0, threshold=1.0e-7, max_level=None, seed=None))]
fn louvain_communities(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    weight: &str,
    resolution: f64,
    threshold: f64,
    max_level: Option<isize>,
    seed: Option<u64>,
) -> PyResult<Vec<Vec<PyObject>>> {
    let gr = extract_graph(g)?;
    let max_level = match max_level {
        Some(level) if level <= 0 => {
            return Err(PyValueError::new_err(
                "max_level argument must be a positive integer or None",
            ));
        }
        Some(level) => Some(level as usize),
        None => None,
    };
    let projection = gr.weighted_undirected_projection(weight);
    let inner = projection.as_ref();
    let result = py.allow_threads(|| {
        fnx_algorithms::louvain_communities(inner, resolution, weight, threshold, max_level, seed)
    });
    Ok(result
        .into_iter()
        .map(|comm| comm.into_iter().map(|n| gr.py_node_key(py, &n)).collect())
        .collect())
}

#[pyfunction]
#[pyo3(signature = (g, communities, resolution=1.0, weight="weight"))]
fn modularity(
    py: Python<'_>,
    g: &Bound<'_, PyAny>,
    communities: &Bound<'_, PyAny>,
    resolution: f64,
    weight: &str,
) -> PyResult<f64> {
    let gr = extract_graph(g)?;
    let normalized_communities = PyList::empty(py);

    let mut comms_strs = Vec::new();
    for comm in communities.try_iter()? {
        let comm = comm?;
        normalized_communities.append(&comm)?;
        let mut comm_strs = Vec::new();
        for node in comm.try_iter()? {
            let node = node?;
            let s = node_key_to_string(py, &node)?;
            comm_strs.push(s);
        }
        comms_strs.push(comm_strs);
    }

    let inner = gr.undirected();
    if !fnx_algorithms::community_partition_is_valid(inner, &comms_strs) {
        return Err(NotAPartition::new_err(format!(
            "{} is not a valid partition of the graph {}",
            normalized_communities.str()?,
            gr.graph_description()
        )));
    }

    py.allow_threads(|| fnx_algorithms::modularity(inner, &comms_strs, resolution, weight))
        .map_err(|_| {
            NotAPartition::new_err(format!(
                "{} is not a valid partition of the graph {}",
                normalized_communities.str().expect("repr should succeed"),
                gr.graph_description()
            ))
        })
}

#[pyfunction]
