    #[test]
    fn multigraph_number_connected_components_matches_materialized_route() {
        let mut graph = MultiGraph::strict();
        assert_eq!(
            super::multigraph_number_connected_components(&graph),
            super::multigraph_number_connected_components_orig_materialized(&graph)
        );

        for node in ["zeta", "alpha", "mu", "theta", "xi"] {
            let _ = graph.add_node(node.to_owned());
        }
        let _ = graph.add_edge("zeta".to_owned(), "alpha".to_owned());
        let _ = graph.add_edge("zeta".to_owned(), "alpha".to_owned());
        let _ = graph.add_edge("alpha".to_owned(), "mu".to_owned());
        let _ = graph.add_edge("theta".to_owned(), "theta".to_owned());
        assert_eq!(
            super::multigraph_number_connected_components(&graph),
            super::multigraph_number_connected_components_orig_materialized(&graph)
        );

        // Exercise read-mutate-read memo invalidation while merging three
        // components into one.
        let _ = graph.add_edge("mu".to_owned(), "theta".to_owned());
        let _ = graph.add_edge("theta".to_owned(), "xi".to_owned());
        assert_eq!(
            super::multigraph_number_connected_components(&graph),
            super::multigraph_number_connected_components_orig_materialized(&graph)
        );
        assert_eq!(super::multigraph_number_connected_components(&graph), 1);
    }

    /// `br-r37-c1-a5rsz`: same-binary paired proof for a count-only traversal
    /// versus the former materialized `connected_components(...).len()` route.
    /// Run through strict remote RCH with:
    /// `cargo test --profile release -p fnx-python --lib
    /// multigraph_number_connected_components_count_ab -- --ignored --nocapture`.
    #[test]
    #[ignore = "measurement; run with release profile, --ignored, and --nocapture"]
    fn multigraph_number_connected_components_count_ab() {
        use std::hint::black_box;
        use std::time::Instant;

        let n = 20_000usize;
        let build_graph = |component_size: usize| {
            let mut graph = MultiGraph::strict();
            for i in 0..n {
                let _ = graph.add_node(format!("count-node-{i:05}"));
            }
            if component_size > 1 {
                for start in (0..n).step_by(component_size) {
                    for offset in 0..component_size {
                        let node = start + offset;
                        let next = start + (offset + 1) % component_size;
                        let _ = graph.add_edge(
                            format!("count-node-{node:05}"),
                            format!("count-node-{next:05}"),
                        );
                    }
                }
            }
            graph
        };
        let fixtures = [
            ("isolates", build_graph(1), n),
            ("pairs", build_graph(2), n / 2),
            ("ring", build_graph(n), 1),
        ];
        let rounds = 31usize;

        for (label, graph, expected) in &fixtures {
            let candidate = super::multigraph_number_connected_components(graph);
            let baseline = super::multigraph_number_connected_components_orig_materialized(graph);
            assert_eq!(
                candidate, baseline,
                "count-only route must match list length"
            );
            assert_eq!(candidate, *expected);

            let time = |candidate_route: bool| -> f64 {
                let start = Instant::now();
                let count = if candidate_route {
                    super::multigraph_number_connected_components(graph)
                } else {
                    super::multigraph_number_connected_components_orig_materialized(graph)
                };
                black_box(count);
                start.elapsed().as_secs_f64()
            };
            for _ in 0..3 {
                black_box(time(true));
                black_box(time(false));
            }

            let paired = |baseline_candidate: bool| -> Vec<f64> {
                let mut ratios = Vec::with_capacity(rounds);
                for round in 0..rounds {
                    let (baseline_time, candidate_time) = if round.is_multiple_of(2) {
                        let baseline_time = time(baseline_candidate);
                        let candidate_time = time(true);
                        (baseline_time, candidate_time)
                    } else {
                        let candidate_time = time(true);
                        let baseline_time = time(baseline_candidate);
                        (baseline_time, candidate_time)
                    };
                    ratios.push(baseline_time / candidate_time);
                }
                ratios
            };
            let report = |name: &str, ratios: &[f64]| {
                let wins = ratios.iter().filter(|&&ratio| ratio > 1.0).count();
                let mut sorted = ratios.to_vec();
                sorted.sort_by(f64::total_cmp);
                println!(
                    "MG_NCC_AB {label}/{name}: median={:.4}x wins={wins}/{rounds} p5_p95=[{:.4},{:.4}]",
                    sorted[rounds / 2],
                    sorted[rounds * 5 / 100],
                    sorted[rounds * 95 / 100],
                );
            };

            println!(
                "MG_NCC_AB {label}: n={n} components={expected} rounds={rounds} (>1 = count-only faster)"
            );
            report("count_vs_materialized", &paired(false));
            report("count_vs_count_null", &paired(true));
        }
    }

    /// `br-r37-c1-7xsg9`: same-binary paired proof for reusing the maintained
    /// MultiGraph integer-adjacency memo in connected-components traversal.
    /// Run through strict remote RCH with:
    /// `cargo test --profile release -p fnx-python --lib
    /// multigraph_connected_components_intadj_ab -- --ignored --nocapture`.
    #[test]
    #[ignore = "measurement; run with release profile, --ignored, and --nocapture"]
    fn multigraph_connected_components_intadj_ab() {
        use std::hint::black_box;
        use std::time::Instant;

        let n = 20_000usize;
        let component_size = 100usize;
        let expected_components = n / component_size;
        let mut graph = MultiGraph::strict();
        for i in 0..n {
            let _ = graph.add_node(format!("component-node-{i:05}"));
        }
        for start in (0..n).step_by(component_size) {
            for offset in 0..component_size {
                let node = start + offset;
                let next = start + (offset + 1) % component_size;
                let chord = start + (offset + 17) % component_size;
                let left = format!("component-node-{node:05}");
                let _ = graph.add_edge(left.clone(), format!("component-node-{next:05}"));
                let _ = graph.add_edge(left, format!("component-node-{chord:05}"));
            }
        }

        let candidate = super::multigraph_connected_components_borrowed(&graph);
        let baseline = super::multigraph_connected_components_orig_string(&graph);
        assert_eq!(
            candidate, baseline,
            "indexed traversal must preserve exact component and discovery order"
        );
        assert_eq!(candidate.len(), expected_components);
        assert!(
            candidate
                .iter()
                .all(|component| component.len() == component_size)
        );

        let time_warm = |indexed: bool| -> f64 {
            let start = Instant::now();
            let components = if indexed {
                super::multigraph_connected_components_borrowed(&graph)
            } else {
                super::multigraph_connected_components_orig_string(&graph)
            };
            black_box(components);
            start.elapsed().as_secs_f64()
        };
        let time_cold = |indexed: bool| -> f64 {
            // `MultiGraph::clone` intentionally starts with an empty integer-adjacency
            // memo. Clone outside the timer so this row measures first-read cache build
            // plus traversal, not graph duplication.
            let fresh = graph.clone();
            let start = Instant::now();
            let components = if indexed {
                super::multigraph_connected_components_borrowed(&fresh)
            } else {
                super::multigraph_connected_components_orig_string(&fresh)
            };
            black_box(components);
            start.elapsed().as_secs_f64()
        };
        for _ in 0..3 {
            black_box(time_warm(true));
            black_box(time_warm(false));
            black_box(time_cold(true));
            black_box(time_cold(false));
        }

        let rounds = 31usize;
        let paired = |time: &dyn Fn(bool) -> f64, baseline_indexed: bool| -> Vec<f64> {
            let mut ratios = Vec::with_capacity(rounds);
            for round in 0..rounds {
                let (baseline_time, candidate_time) = if round.is_multiple_of(2) {
                    let baseline_time = time(baseline_indexed);
                    let candidate_time = time(true);
                    (baseline_time, candidate_time)
                } else {
                    let candidate_time = time(true);
                    let baseline_time = time(baseline_indexed);
                    (baseline_time, candidate_time)
                };
                ratios.push(baseline_time / candidate_time);
            }
            ratios
        };
        let report = |name: &str, ratios: &[f64]| {
            let wins = ratios.iter().filter(|&&ratio| ratio > 1.0).count();
            let mut sorted = ratios.to_vec();
            sorted.sort_by(|left, right| left.partial_cmp(right).unwrap());
            println!(
                "MG_CC_AB {name}: median={:.4}x wins={wins}/{rounds} p5_p95=[{:.4},{:.4}]",
                sorted[rounds / 2],
                sorted[rounds * 5 / 100],
                sorted[rounds * 95 / 100],
            );
        };

        println!(
            "MG_CC_AB n={n} components={expected_components} rounds={rounds} (>1 = indexed faster)"
        );
        report("WARM_index_vs_string", &paired(&time_warm, false));
        report("WARM_NULL_index_vs_index", &paired(&time_warm, true));
        report("COLD_index_vs_string", &paired(&time_cold, false));
        report("COLD_NULL_index_vs_index", &paired(&time_cold, true));
    }

    /// br-r37-c1-thp6w slice 2: paired-interleaved median A/B for the integer-adjacency
    /// (`with_int_adjacency` + `Vec<bool>`) MultiGraph BFS vs the pre-lever String BFS
    /// (`mg.neighbors` `Vec<&str>` per pop + `HashSet<&str>`), in ONE binary / ONE worker
    /// with a NULL control. Measures the ALL-PAIRS scenario (BFS from every node) so the
    /// revision-keyed memo is built once and reused across sources — the maintained-mirror
    /// win. `#[ignore]` (measurement); run with
    /// `cargo test --release -p fnx-python --lib mg_bfs_intadj_ab -- --ignored --nocapture`.
    #[test]
    #[ignore = "measurement; run with --release --ignored --nocapture"]
    fn mg_bfs_intadj_ab() {
        use std::hint::black_box;
        use std::time::Instant;

        // Deterministic connected MultiGraph: a ring (connectivity) + pseudo-random chords
        // and some parallel edges (so rows have several distinct neighbors). All-pairs BFS
        // over it exercises V independent single-source calls reusing one memo.
        let n = 400usize;
        let mut g = MultiGraph::strict();
        for i in 0..n {
            let _ = g.add_node(format!("n{i}"));
        }
        for i in 0..n {
            let _ = g.add_edge(format!("n{i}"), format!("n{}", (i + 1) % n));
        }
        for i in 0..n {
            for k in [7usize, 19, 43] {
                let j = (i.wrapping_mul(1_000_003).wrapping_add(k)) % n;
                if j != i {
                    let _ = g.add_edge(format!("n{i}"), format!("n{j}"));
                }
            }
        }
        let names: Vec<String> = g.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();

        // Byte-exact parity: integer BFS == String BFS for EVERY source.
        for src in &names {
            assert_eq!(
                super::multigraph_sssp_length_with_parents(&g, src, None),
                super::multigraph_sssp_length_with_parents_orig_string(&g, src, None),
                "integer-adjacency MultiGraph BFS must equal the String baseline for {src}"
            );
        }

        // All-pairs: BFS from every node. `lever` picks the integer or String primitive.
        let all_pairs = |lever: bool| -> usize {
            let mut acc = 0usize;
            for src in &names {
                let r = if lever {
                    super::multigraph_sssp_length_with_parents(&g, src, None)
                } else {
                    super::multigraph_sssp_length_with_parents_orig_string(&g, src, None)
                };
                acc = acc.wrapping_add(r.len());
            }
            acc
        };
        let time = |lever: bool| -> f64 {
            let t0 = Instant::now();
            black_box(all_pairs(lever));
            t0.elapsed().as_secs_f64()
        };
        for _ in 0..3 {
            black_box(time(true));
            black_box(time(false));
        }
        let median = |v: &[f64]| {
            let mut s = v.to_vec();
            s.sort_by(|a, b| a.partial_cmp(b).unwrap());
            s[s.len() / 2]
        };
        let rounds = 61usize;
        let paired = |cand: bool, base: bool| -> Vec<f64> {
            let mut v = Vec::with_capacity(rounds);
            for r in 0..rounds {
                let (tb, tc) = if r % 2 == 0 {
                    let b = time(base);
                    let c = time(cand);
                    (b, c)
                } else {
                    let c = time(cand);
                    let b = time(base);
                    (b, c)
                };
                v.push(tb / tc);
            }
            v
        };
        let report = |name: &str, ratios: &[f64]| {
            let wins = ratios.iter().filter(|&&r| r > 1.0).count();
            let mut sorted = ratios.to_vec();
            sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
            println!(
                "MG_BFS_AB {name}: median={:.4}x win_rate={wins}/{rounds} \
                 p5_p95=[{:.4},{:.4}]",
                median(ratios),
                sorted[rounds * 5 / 100],
                sorted[rounds * 95 / 100],
            );
        };
        println!("MG_BFS_AB n={n} all_pairs rounds={rounds} (>1 = integer-adjacency faster)");
        report("INTADJ_vs_string", &paired(true, false));
        report("NULL_intadj_vs_intadj", &paired(true, true));
    }

    /// br-r37-c1-zid1b straggler: paired-interleaved median A/B for the CSR MultiDiGraph BFS
    /// (`mdg.csr()` + `Vec<bool>`) vs the pre-lever String BFS (`mdg.successors` `Vec<&str>` per
    /// pop + `HashSet<&str>`), in ONE binary / ONE worker with a NULL control. ALL-PAIRS (BFS
    /// from every node) so the revision-cached CSR is built once and reused. `#[ignore]`; run
    /// `cargo test --release -p fnx-python --lib mdg_bfs_csr_ab -- --ignored --nocapture`.
    #[test]
    #[ignore = "measurement; run with --release --ignored --nocapture"]
    fn mdg_bfs_csr_ab() {
        use std::hint::black_box;
        use std::time::Instant;

        let n = 400usize;
        let mut g = MultiDiGraph::new(CompatibilityMode::Strict);
        for i in 0..n {
            let _ = g.add_node(format!("n{i}"));
        }
        for i in 0..n {
            let _ = g.add_edge(format!("n{i}"), format!("n{}", (i + 1) % n));
        }
        for i in 0..n {
            for k in [7usize, 19, 43] {
                let j = (i.wrapping_mul(1_000_003).wrapping_add(k)) % n;
                if j != i {
                    let _ = g.add_edge(format!("n{i}"), format!("n{j}"));
                }
            }
        }
        let names: Vec<String> = g.nodes_ordered().iter().map(|s| (*s).to_owned()).collect();

        for src in &names {
            assert_eq!(
                super::multidigraph_sssp_length_with_parents(&g, src, None),
                super::multidigraph_sssp_length_with_parents_orig_string(&g, src, None),
                "CSR MultiDiGraph BFS must equal the String baseline for {src}"
            );
        }

        let all_pairs = |lever: bool| -> usize {
            let mut acc = 0usize;
            for src in &names {
                let r = if lever {
                    super::multidigraph_sssp_length_with_parents(&g, src, None)
                } else {
                    super::multidigraph_sssp_length_with_parents_orig_string(&g, src, None)
                };
                acc = acc.wrapping_add(r.len());
            }
            acc
        };
        let time = |lever: bool| -> f64 {
            let t0 = Instant::now();
            black_box(all_pairs(lever));
            t0.elapsed().as_secs_f64()
        };
        for _ in 0..3 {
            black_box(time(true));
            black_box(time(false));
        }
        let median = |v: &[f64]| {
            let mut s = v.to_vec();
            s.sort_by(|a, b| a.partial_cmp(b).unwrap());
            s[s.len() / 2]
        };
        let rounds = 61usize;
        let paired = |cand: bool, base: bool| -> Vec<f64> {
            let mut v = Vec::with_capacity(rounds);
            for r in 0..rounds {
                let (tb, tc) = if r % 2 == 0 {
                    let b = time(base);
                    let c = time(cand);
                    (b, c)
                } else {
                    let c = time(cand);
                    let b = time(base);
                    (b, c)
                };
                v.push(tb / tc);
            }
            v
        };
        let report = |name: &str, ratios: &[f64]| {
            let wins = ratios.iter().filter(|&&r| r > 1.0).count();
            let mut sorted = ratios.to_vec();
            sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
            println!(
                "MDG_BFS_AB {name}: median={:.4}x win_rate={wins}/{rounds} \
                 p5_p95=[{:.4},{:.4}]",
                median(ratios),
                sorted[rounds * 5 / 100],
                sorted[rounds * 95 / 100],
            );
        };
        println!("MDG_BFS_AB n={n} all_pairs rounds={rounds} (>1 = CSR faster)");
        report("CSR_vs_string", &paired(true, false));
        report("NULL_csr_vs_csr", &paired(true, true));
    }

    /// br-r37-c1-mgdt3: paired-interleaved median A/B of the interned-keys allocation
    /// lever against its exact pre-change baseline, inside ONE binary / ONE worker so
    /// there is no cross-worker ratio noise. Also runs a NULL control (interned vs
    /// interned) to establish the harness floor. Marked `#[ignore]` — it is a
    /// measurement, run with:
    /// `cargo test --release -p fnx-python --lib dijkstra_alloc_ab_median -- --ignored --nocapture`.
    #[test]
    #[ignore = "measurement; run with --release --ignored --nocapture"]
    fn dijkstra_alloc_ab_median() {
        use std::hint::black_box;
        use std::time::Instant;

        // Deterministic connected weighted string-keyed MultiGraph: a ring (for
        // connectivity) plus random parallel chords (so the per-call node table +
        // index HashMap the lever removes are non-trivial). n=800 exercises the O(n)
        // allocations the lever targets.
        let n = 800usize;
        let mut g = MultiGraph::strict();
        for i in 0..n {
            let _ = g.add_node(i.to_string());
        }
        let mut x = 0x2545_F491_4F6C_DD1Du64;
        let mut next = || {
            x ^= x << 13;
            x ^= x >> 7;
            x ^= x << 17;
            x
        };
        let w_attr = |val: i64| -> AttrMap {
            let mut a = AttrMap::new();
            a.insert("weight".to_owned(), fnx_runtime::CgseValue::from(val));
            a
        };
        for i in 0..n {
            let _ = g.add_edge_with_attrs(
                i.to_string(),
                ((i + 1) % n).to_string(),
                w_attr(((next() % 9) + 1) as i64),
            );
        }
        for _ in 0..(n * 3) {
            let (u, v) = ((next() as usize) % n, (next() as usize) % n);
            if u != v {
                let _ = g.add_edge_with_attrs(
                    u.to_string(),
                    v.to_string(),
                    w_attr(((next() % 9) + 1) as i64),
                );
            }
        }
        let (s, t) = ("0".to_owned(), (n / 2).to_string());

        // Arms: 0 = lazy (current production, interned string traversal),
        //       1 = intadj (cache-friendly integer adjacency, build-once SoA).
        let call = |arm: u8| {
            if arm == 0 {
                super::multigraph_dijkstra_path_to_target_lazy(&g, &s, &t, "weight")
            } else {
                super::multigraph_dijkstra_path_to_target_intadj(&g, &s, &t, "weight")
            }
        };
        // Parity: intadj must be byte-identical to the lazy production AND to the
        // pre-interned original (transitively pins the whole lineage).
        let bits = |arm: u8| call(arm).map(|(d, p, i)| (d.to_bits(), p, i));
        let orig_bits = super::multigraph_dijkstra_path_to_target_lazy_orig(&g, &s, &t, "weight")
            .map(|(d, p, i)| (d.to_bits(), p, i));
        assert_eq!(bits(0), bits(1), "intadj must match the lazy production");
        assert_eq!(
            bits(0),
            orig_bits,
            "lazy must match the pre-interned original"
        );
        assert!(call(0).is_some(), "fixture must have a path");

        const CALLS: usize = 300;
        let time = |arm: u8| -> f64 {
            let t0 = Instant::now();
            for _ in 0..CALLS {
                black_box(&call(arm));
            }
            t0.elapsed().as_secs_f64()
        };
        for _ in 0..5 {
            black_box(time(0));
            black_box(time(1));
        }

        let median = |v: &[f64]| {
            let mut s = v.to_vec();
            s.sort_by(|a, b| a.partial_cmp(b).unwrap());
            s[s.len() / 2]
        };
        let rounds = 121usize;
        let paired = |cand: u8, base: u8| -> Vec<f64> {
            let mut v = Vec::with_capacity(rounds);
            for r in 0..rounds {
                let (tb, tc) = if r % 2 == 0 {
                    let b = time(base);
                    let c = time(cand);
                    (b, c)
                } else {
                    let c = time(cand);
                    let b = time(base);
                    (b, c)
                };
                v.push(tb / tc);
            }
            v
        };
        let report = |name: &str, ratios: &[f64]| {
            let wins = ratios.iter().filter(|&&r| r > 1.0).count();
            let mut sorted = ratios.to_vec();
            sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
            let (lo, hi) = (sorted[rounds * 5 / 100], sorted[rounds * 95 / 100]);
            println!(
                "DIJKSTRA_ALLOC_AB {name}: median={:.4}x win_rate={wins}/{rounds} \
                 p5_p95=[{lo:.4},{hi:.4}]",
                median(ratios),
            );
        };
        println!("DIJKSTRA_ALLOC_AB n={n} calls={CALLS} rounds={rounds} (>1 = cand faster)");
        // THE LEVER TO GATE: intadj (cache-friendly SoA) vs lazy (current production).
        report("INTADJ_vs_lazy", &paired(1, 0));
        // NULL floor: lazy vs lazy.
        report("NULL_lazy_vs_lazy", &paired(0, 0));
    }

